-- ============================================================
-- CONFIG PERSISTENCE
-- ============================================================

local CONFIG_FILE_NAME = "AccelerantHubConfig.json"
local CONFIG_FILE_PATHS = {
	"workspace/AccelerantHubConfig.json",
	CONFIG_FILE_NAME,
}

function getExecutorFileApi()
	return {
		isfile = syn_io_isfile or isfile,
		read = syn_io_read or readfile,
		write = syn_io_write or writefile,
		makefolder = syn_io_makefolder or makefolder,
		isfolder = syn_io_isfolder or isfolder,
	}
end

function ensureConfigWorkspace(fileApi)
	if type(fileApi.isfolder) == "function" and type(fileApi.makefolder) == "function" then
		local ok, exists = pcall(fileApi.isfolder, "workspace")
		if ok and not exists then
			pcall(fileApi.makefolder, "workspace")
		end
	end
end

function verifyConfigWrite(fileApi, path, expected)
	if type(fileApi.isfile) == "function" then
		local ok, exists = pcall(fileApi.isfile, path)
		if not ok or not exists then
			return false
		end
	end

	if type(fileApi.read) == "function" then
		local ok, contents = pcall(fileApi.read, path)
		if not ok or contents ~= expected then
			return false
		end
	end

	return true
end

function serializeConfigValue(value)
	local valueType = typeof(value)
	if valueType == "Vector3" then
		return {
			__type = "Vector3",
			X = value.X,
			Y = value.Y,
			Z = value.Z,
		}
	end
	if valueType == "EnumItem" then
		return {
			__type = "EnumItem",
			EnumType = tostring(value.EnumType),
			Name = value.Name,
		}
	end
	if valueType == "table" then
		local out = {}
		for key, child in value do
			out[key] = serializeConfigValue(child)
		end
		return out
	end
	return value
end

function deserializeConfigValue(value)
	if type(value) ~= "table" then return value end

	if value.__type == "Vector3" then
		return Vector3.new(tonumber(value.X) or 0, tonumber(value.Y) or 0, tonumber(value.Z) or 0)
	end

	if value.__type == "EnumItem" then
		if value.EnumType == "Enum.KeyCode" and Enum.KeyCode[value.Name] then
			return Enum.KeyCode[value.Name]
		end
		return nil
	end

	local out = {}
	for key, child in value do
		out[key] = deserializeConfigValue(child)
	end
	return out
end

function exportMenuConfig()
	local out = {}
	for key, value in CONFIG do
		out[key] = serializeConfigValue(value)
	end
	return out
end

function applyMenuConfig(saved)
	if type(saved) ~= "table" then return false, "invalid config payload" end

	for key, value in saved do
		if CONFIG[key] ~= nil then
			local decoded = deserializeConfigValue(value)
			if decoded ~= nil then
				CONFIG[key] = decoded
			end
		end
	end

	return true
end

function saveMenuConfig()
	local fileApi = getExecutorFileApi()
	if type(fileApi.write) ~= "function" then
		return false, "executor file write API is unavailable"
	end
	ensureConfigWorkspace(fileApi)

	local payload = {
		Version = 1,
		SavedAt = os.time(),
		Config = exportMenuConfig(),
	}
	local json = HttpService:JSONEncode(payload)
	local lastErr = nil
	for _, path in CONFIG_FILE_PATHS do
		local ok, err = pcall(fileApi.write, path, json)
		if ok and verifyConfigWrite(fileApi, path, json) then
			return true, path
		end
		lastErr = err or "write verification failed for " .. path
	end
	return false, tostring(lastErr or "write failed")
end

function loadMenuConfig()
	local fileApi = getExecutorFileApi()
	if type(fileApi.isfile) ~= "function" or type(fileApi.read) ~= "function" then
		return false, "executor file read API is unavailable"
	end
	local path, contents
	for _, candidate in CONFIG_FILE_PATHS do
		local existsOk, exists = pcall(fileApi.isfile, candidate)
		if existsOk and exists then
			local readOk, readResult = pcall(fileApi.read, candidate)
			if readOk then
				path = candidate
				contents = readResult
				break
			end
		end
	end
	if not path then
		return false, "config file not found"
	end

	local decodedOk, decoded = pcall(function()
		return HttpService:JSONDecode(contents)
	end)
	if not decodedOk then
		return false, tostring(decoded)
	end

	local applied, applyErr = applyMenuConfig(decoded.Config or decoded)
	if not applied then
		return false, applyErr
	end

	return true, path
end


