local cachedAccelerantLogoAsset = nil

function decodeBase64(data)
	local alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
	local lookup = {}
	for i = 1, #alphabet do
		lookup[string.sub(alphabet, i, i)] = i - 1
	end

	local out = {}
	local buffer = 0
	local bits = 0
	for i = 1, #data do
		local char = string.sub(data, i, i)
		if char == "=" then
			break
		end
		local value = lookup[char]
		if value then
			buffer = buffer * 64 + value
			bits += 6
			while bits >= 8 do
				bits -= 8
				local byte = math.floor(buffer / (2 ^ bits)) % 256
				table.insert(out, string.char(byte))
				buffer = buffer % (2 ^ bits)
			end
		end
	end
	return table.concat(out)
end

function getCustomAssetPath(path)
	if type(getcustomasset) == "function" then
		local ok, result = pcall(getcustomasset, path)
		if ok and result then return result end
	end
	if type(getsynasset) == "function" then
		local ok, result = pcall(getsynasset, path)
		if ok and result then return result end
	end
	return nil
end

function ensureAccelerantLogoAsset()
	if cachedAccelerantLogoAsset then
		return cachedAccelerantLogoAsset
	end

	local fileApi = getExecutorFileApi()
	if type(fileApi.write) ~= "function" then
		return nil
	end

	ensureConfigWorkspace(fileApi)
	local pngData = nil
	for _, path in { ACCELERANT_LOGO_PATH, ACCELERANT_LOGO_FALLBACK_PATH } do
		local exists = false
		if type(fileApi.isfile) == "function" then
			local ok, result = pcall(fileApi.isfile, path)
			exists = ok and result == true
		end
		if not exists then
			pngData = pngData or decodeBase64(table.concat(ACCELERANT_LOGO_BASE64))
			pcall(fileApi.write, path, pngData)
		end
		local assetPath = getCustomAssetPath(path)
		if assetPath then
			cachedAccelerantLogoAsset = assetPath
			return cachedAccelerantLogoAsset
		end
	end

	return nil
end
-- ============================================================
-- HELPERS
-- ============================================================

function hasTag(inst, tag)
	if not inst then return false end
	if typeof(inst.HasTag) == "function" then
		return inst:HasTag(tag)
	end
	return CollectionService:HasTag(inst, tag)
end

local PRIMARY_PART_CANDIDATES = {
	"HumanoidRootPart",
	"LowerTorso",
	"UpperTorso",
	"Torso",
	"Head",
}

function getPrimaryPartCandidate(model)
	if not model or not model:IsA("Model") then
		return nil
	end

	for _, name in PRIMARY_PART_CANDIDATES do
		local candidate = model:FindFirstChild(name)
		if candidate and candidate:IsA("BasePart") then
			return candidate
		end
	end

	local primary = model.PrimaryPart
	if primary and primary.Parent == model and primary:IsA("BasePart") then
		return primary
	end

	for _, desc in model:GetDescendants() do
		if desc:IsA("BasePart") then
			return desc
		end
	end

	return nil
end

function ensureModelPrimaryPart(model)
	local candidate = getPrimaryPartCandidate(model)
	if not model or not candidate then
		return nil
	end

	if model.PrimaryPart ~= candidate then
		pcall(function()
			model.PrimaryPart = candidate
		end)
	end

	return model.PrimaryPart or candidate
end

function getCharacter()
	local char = LP and LP.Character
	if char then
		ensureModelPrimaryPart(char)
		if char.PrimaryPart then
			return char
		end
	end
end

function findLoadedSessionManager()
	if moduleCache.sessionManager and isSessionManagerTable(moduleCache.sessionManager) then
		return moduleCache.sessionManager
	end
	moduleCache.sessionManager = nil
	if typeof(getgc) ~= "function" then
		return nil
	end

	for _, obj in getgc(true) do
		if isSessionManagerTable(obj) then
			moduleCache.sessionManager = obj
			return obj
		end
	end

	return nil
end

function isSessionManagerTable(tbl)
	local slotLoaded = type(tbl) == "table" and rawget(tbl, "SlotLoaded") or nil
	local slotUnloaded = type(tbl) == "table" and rawget(tbl, "SlotUnloaded") or nil
	local loadedSignalLike = type(slotLoaded) == "table"
		and (type(slotLoaded.Connect) == "function" or type(slotLoaded.Once) == "function")
	local unloadedSignalLike = type(slotUnloaded) == "table"
		and (type(slotUnloaded.Connect) == "function" or type(slotUnloaded.Once) == "function")
	return type(tbl) == "table"
		and type(rawget(tbl, "GetSlot")) == "function"
		and type(rawget(tbl, "GetSaveFile")) == "function"
		and type(rawget(tbl, "GetSession")) == "function"
		and type(rawget(tbl, "ObserveLocalSlotChanged")) == "function"
		and type(rawget(tbl, "ObservePlayerSlotChanged")) == "function"
		and loadedSignalLike
		and unloadedSignalLike
end

function resolveSessionManagerFromFunction(fn)
	if type(fn) ~= "function" or not debug or type(debug.getupvalue) ~= "function" then
		return nil
	end

	for i = 1, 60 do
		local ok, _, value = pcall(debug.getupvalue, fn, i)
		if not ok then
			break
		end
		if isSessionManagerTable(value) then
			moduleCache.sessionManager = value
			return value
		end
	end

	return nil
end

function findSessionManagerFromQuestRuntime(questClient)
	if moduleCache.sessionManager then
		return moduleCache.sessionManager
	end

	if type(questClient) == "table" then
		local direct = resolveSessionManagerFromFunction(rawget(questClient, "_init"))
			or resolveSessionManagerFromFunction(rawget(questClient, "GetQuestByName"))
		if direct then
			return direct
		end
	end

	local questModule = ReplicatedStorage:FindFirstChild("Client")
		and ReplicatedStorage.Client:FindFirstChild("Quest")
		and ReplicatedStorage.Client.Quest:FindFirstChild("QuestClient")
	if not questModule or not questModule:IsA("ModuleScript") or type(getscriptclosure) ~= "function" then
		return nil
	end

	local ok, closure = pcall(getscriptclosure, questModule)
	if not ok then
		return nil
	end

	return resolveSessionManagerFromFunction(closure)
end

function tryLoadSessionManagerModule()
	if moduleCache.sessionManager and isSessionManagerTable(moduleCache.sessionManager) then
		return moduleCache.sessionManager
	end

	local shared = ReplicatedStorage:FindFirstChild("Shared")
	local playerData = shared and shared:FindFirstChild("PlayerData")
	local sessionModule = playerData and playerData:FindFirstChild("SessionManager")
	if not sessionModule or not sessionModule:IsA("ModuleScript") then
		return nil
	end

	local env = typeof(getrenv) == "function" and getrenv() or nil
	local req = env and rawget(env, "require") or nil
	if type(req) ~= "function" then
		return nil
	end

	local ok, manager = pcall(req, sessionModule)
	if ok and isSessionManagerTable(manager) then
		moduleCache.sessionManager = manager
		return manager
	end

	return nil
end

function getLoadedSessionState()
	local manager = findLoadedSessionManager() or tryLoadSessionManagerModule()
	if not manager then
		return nil, nil, nil, "SessionManager is not loaded yet"
	end

	local slotOk, slot = pcall(function()
		return manager.GetSlot(LP)
	end)
	if not slotOk or not slot then
		return manager, nil, nil, "local slot is unavailable"
	end

	local saveOk, saveFile = pcall(function()
		return manager.GetSaveFile(LP)
	end)
	if not saveOk or not saveFile then
		return manager, slot, nil, "save file is unavailable"
	end

	return manager, slot, saveFile, nil
end

function getClientTagData()
	return LP and LP:FindFirstChild("ClientTagData")
end

function waitForCondition(timeoutSeconds, predicate, intervalSeconds)
	local deadline = os.clock() + (timeoutSeconds or 1)
	local interval = intervalSeconds or 0.05

	repeat
		local ok, result = pcall(predicate)
		if ok and result then
			return true, result
		end
		task.wait(interval)
	until os.clock() >= deadline

	return false, nil
end

function valuesEqual(left, right)
	local leftType = typeof(left)
	local rightType = typeof(right)
	if leftType ~= rightType then
		return false
	end

	if leftType == "Color3" then
		return math.abs(left.R - right.R) <= 0.001
			and math.abs(left.G - right.G) <= 0.001
			and math.abs(left.B - right.B) <= 0.001
	end

	if leftType == "table" then
		local leftCount = 0
		local rightCount = 0
		for key in left do
			leftCount += 1
			if not valuesEqual(left[key], right[key]) then
				return false
			end
		end
		for _ in right do
			rightCount += 1
		end
		return leftCount == rightCount
	end

	return left == right
end

function isLoadedChangeAppearanceModule(tbl)
	if type(tbl) ~= "table" or type(rawget(tbl, "Open")) ~= "function" then
		return false
	end
	if not debug or type(debug.getupvalue) ~= "function" then
		return false
	end

	local playerGui = LP and LP:FindFirstChild("PlayerGui")
	local expectedUi = playerGui and playerGui:FindFirstChild("ChangeAppearanceUI")
	if not expectedUi then
		return false
	end

	local sawPlayer = false
	local sawUi = false
	for i = 1, 40 do
		local ok, name, value = pcall(debug.getupvalue, rawget(tbl, "Open"), i)
		if not ok or not name then
			break
		end
		if value == LP then
			sawPlayer = true
		elseif value == expectedUi then
			sawUi = true
		end
	end

	return sawPlayer and sawUi
end

function findLoadedChangeAppearanceModule()
	if moduleCache.changeAppearance then
		return moduleCache.changeAppearance
	end
	if typeof(getgc) ~= "function" then
		return nil
	end

	local playerGui = LP and LP:FindFirstChild("PlayerGui")
	if not (playerGui and playerGui:FindFirstChild("ChangeAppearanceUI")) then
		return nil
	end

	for _, obj in getgc(true) do
		if isLoadedChangeAppearanceModule(obj) then
			moduleCache.changeAppearance = obj
			return obj
		end
	end

	return nil
end

function encode(value, seen)
	seen = seen or {}
	local t = typeof(value)
	if t == "Instance" then
		local gid = value:GetAttribute("Gid")
		if gid then return { __type = "Instance", value = gid } end
		return value
	end
	if t ~= "table" then return value end
	if seen[value] then return nil end
	seen[value] = true
	local c = table.clone(value)
	for k, v in c do
		c[k] = encode(v, seen)
	end
	return c
end

function getMeleeTool(character)
	for _, child in character:GetChildren() do
		if child:IsA("Tool") and hasTag(child, "Melee") then
			return child
		end
	end
end

function releaseFarmMouse()
	if not state.farmMouseSaved then
		state.farmMouseSaved = {
			behavior = UIS.MouseBehavior,
			icon = UIS.MouseIconEnabled,
		}
	end
	UIS.MouseBehavior = Enum.MouseBehavior.Default
	UIS.MouseIconEnabled = true
end

function restoreFarmMouse()
	local saved = state.farmMouseSaved
	if not saved then
		return
	end
	UIS.MouseBehavior = saved.behavior
	UIS.MouseIconEnabled = saved.icon
	state.farmMouseSaved = nil
end

