-- EQUIP STRONGEST TOOL (respawn)
-- ============================================================

local WEAPON_SUBTYPES = { Melee = true, Ranged = true }

local STATIC_WEAPON_DB = {
	CricketBat = { subtype = "Melee", damage = 7, cooldown = 0.95 },
	Axe = { subtype = "Melee", damage = 20, cooldown = 1.5 },
	Machete = { subtype = "Melee", damage = 10, cooldown = 0.75 },
	Pickaxe = { subtype = "Melee", damage = 16, cooldown = 1.2 },
	Shovel = { subtype = "Melee", damage = 18, cooldown = 1.35 },
	FencingFoil = { subtype = "Melee", damage = 7, cooldown = 0.5 },
	Wrench = { subtype = "Melee", damage = 10, cooldown = 0.8 },
	KitchenKnife = { subtype = "Melee", damage = 7, cooldown = 0.55 },
	Crowbar = { subtype = "Melee", damage = 15, cooldown = 1 },
	BaseballBat = { subtype = "Melee", damage = 8, cooldown = 1 },
	Baton = { subtype = "Melee", damage = 7, cooldown = 0.7 },
	Katana = { subtype = "Melee", damage = 12, cooldown = 0.6 },
	Stick = { subtype = "Melee", damage = 5, cooldown = 0.75 },
	GolfClub = { subtype = "Melee", damage = 12, cooldown = 1.1 },
	Fists = { subtype = "Melee", damage = 6, cooldown = 0.5 },
	Lightsword = { subtype = "Melee", damage = 100, cooldown = 0.6 },
	Sword = { subtype = "Melee", damage = 13, cooldown = 0.8 },
	Revolver = { subtype = "Ranged", bodyDamage = 9, headDamage = 18, bulletsPerSecond = 1, blastMax = 0 },
	Pistol = { subtype = "Ranged", bodyDamage = 6, headDamage = 12, bulletsPerSecond = 3, blastMax = 0 },
	SubmachineGun = { subtype = "Ranged", bodyDamage = 2, headDamage = 4, bulletsPerSecond = 12, blastMax = 0 },
	LightMachineGun = { subtype = "Ranged", bodyDamage = 6, headDamage = 10, bulletsPerSecond = 12, blastMax = 0 },
	Shotgun = { subtype = "Ranged", bodyDamage = 4, headDamage = 6, bulletsPerSecond = 1, blastMax = 0 },
	Sniper = { subtype = "Ranged", bodyDamage = 15, headDamage = 30, bulletsPerSecond = 0.6, blastMax = 0 },
	BoltActionRifle = { subtype = "Ranged", bodyDamage = 19, headDamage = 38, bulletsPerSecond = 0.6, blastMax = 0 },
	RocketLauncher = { subtype = "Ranged", bodyDamage = 40, headDamage = 40, bulletsPerSecond = 1, blastMax = 30 },
	AssaultRifle = { subtype = "Ranged", bodyDamage = 3, headDamage = 6, bulletsPerSecond = 8, blastMax = 0 },
	Crossbow = { subtype = "Ranged", bodyDamage = 25, headDamage = 50, bulletsPerSecond = 0.75, blastMax = 0 },
}

local equipStrongest = {
	invCmd = nil,
	hotbarEquip = nil,
	hotbarUnequip = nil,
	hotbarClient = nil,
	hotbarUnavailable = false,
}

function slotIdMatches(a, b)
	return a == b or tostring(a) == tostring(b)
end

function isWeaponTool(tool)
	return hasTag(tool, "Melee") or hasTag(tool, "Ranged") or STATIC_WEAPON_DB[tool.Name] ~= nil
end

function getWeaponSubtype(name)
	local data = STATIC_WEAPON_DB[name]
	return data and data.subtype
end

function getToolStrength(itemSlot)
	local itemName = itemSlot.Item.Name
	local data = STATIC_WEAPON_DB[itemName]
	if not data then
		return 0
	end
	if data.subtype == "Melee" then
		local r = math.min(itemSlot.Item.Rarity or 1, 4)
		return data.damage / data.cooldown + (r - 1) * 10
	end
	local body = data.bodyDamage
	local head = data.headDamage > 0 and data.headDamage or data.bodyDamage
	local avg = (body + head) / 2
	if data.blastMax and data.blastMax > 0 then
		avg = math.max(avg, data.blastMax)
	end
	return avg * data.bulletsPerSecond
end

function isHotbarClientTable(tbl)
	if type(tbl) ~= "table" then
		return false
	end
	local equipped = rawget(tbl, "Equipped")
	local unequipped = rawget(tbl, "Unequipped")
	if not equipped or not unequipped then
		return false
	end
	if type(rawget(tbl, "Equip")) ~= "function" then
		return false
	end
	if type(rawget(tbl, "Unequip")) ~= "function" then
		return false
	end
	if type(equipped.Fire) ~= "function" or type(equipped.Connect) ~= "function" then
		return false
	end
	return true
end

function cacheHotbarClient(hc, method)
	if hc then
		equipStrongest.hotbarClient = hc
		log("Equip → HotbarClient via " .. method)
	end
	return hc
end

function scanGcForHotbarClient(includeTables)
	if typeof(getgc) ~= "function" then
		return nil
	end
	for _, obj in getgc(includeTables) do
		if isHotbarClientTable(obj) then
			return cacheHotbarClient(obj, "getgc")
		end
	end
	return nil
end

function scanUpvaluesForHotbarClient()
	if typeof(getgc) ~= "function" or not debug or not debug.getupvalue then
		return nil
	end

	local targetNames = { HotbarClient = true, t = true }

	for _, fn in getgc() do
		if type(fn) == "function" then
			local fnName = ""
			pcall(function()
				fnName = debug.info(fn, "n") or ""
			end)
			local fromHotbar = fnName == "Equip" or fnName == "DoEquip" or fnName == "DoUnequip"
				or fnName == "GetEquippedSlot" or fnName == "GetEquippedTool"

			for i = 1, 60 do
				local ok, name, val = pcall(debug.getupvalue, fn, i)
				if not ok or not name then
					break
				end

				if isHotbarClientTable(val) then
					return cacheHotbarClient(val, fromHotbar and ("upvalue:" .. fnName) or "upvalue")
				end

				if targetNames[name] and type(val) == "table" and isHotbarClientTable(val) then
					return cacheHotbarClient(val, "upvalue:" .. name)
				end
			end
		end
	end
	return nil
end

function scanScriptClosureForHotbarClient()
	if typeof(getscriptclosure) ~= "function" then
		return nil
	end
	local hotbarMod = ReplicatedStorage:FindFirstChild("Client")
		and ReplicatedStorage.Client:FindFirstChild("Hotbar")
		and ReplicatedStorage.Client.Hotbar:FindFirstChild("HotbarClient")
	if not hotbarMod or not hotbarMod:IsA("ModuleScript") then
		return nil
	end

	local ok, closure = pcall(getscriptclosure, hotbarMod)
	if not ok or type(closure) ~= "function" or not debug or not debug.getupvalue then
		return nil
	end

	for i = 1, 60 do
		local nOk, name, val = pcall(debug.getupvalue, closure, i)
		if not nOk or not name then
			break
		end
		if isHotbarClientTable(val) then
			return cacheHotbarClient(val, "getscriptclosure")
		end
	end
	return nil
end

function findHotbarClient()
	if equipStrongest.hotbarClient then
		return equipStrongest.hotbarClient
	end

	return scanGcForHotbarClient(true)
		or scanGcForHotbarClient(false)
		or scanUpvaluesForHotbarClient()
		or scanScriptClosureForHotbarClient()
end

function findInventoryManager()
	if typeof(getgc) ~= "function" then
		return nil
	end
	for _, obj in getgc(true) do
		if type(obj) == "table"
			and type(rawget(obj, "GetInventory")) == "function"
			and type(rawget(obj, "GetInventoryAsync")) == "function"
			and type(rawget(obj, "GetInventories")) == "function" then
			return obj
		end
	end
	return nil
end

function findInventoryObject()
	local manager = findInventoryManager()
	if manager and LP then
		local inv = manager:GetInventory(LP)
		if inv then
			return inv
		end
	end
	if typeof(getgc) ~= "function" then
		return nil
	end
	for _, obj in getgc(true) do
		if type(obj) == "table"
			and type(rawget(obj, "GetItemSlots")) == "function"
			and type(rawget(obj, "GetHotbarItems")) == "function"
			and type(rawget(obj, "IsItemInHotbar")) == "function" then
			return obj
		end
	end
	return nil
end

function getEquipNetwork()
	local net = ReplicatedStorage:WaitForChild("Network", 5)
	if not net then
		return false
	end
	local inv = net:WaitForChild("Inventory", 3)
	local hotbar = net:WaitForChild("Hotbar", 3)
	if not inv or not hotbar then
		return false
	end
	equipStrongest.invCmd = inv:WaitForChild("Commands", 3)
	equipStrongest.hotbarEquip = hotbar:WaitForChild("Equip", 3)
	equipStrongest.hotbarUnequip = hotbar:WaitForChild("Unequip", 3)
	return equipStrongest.invCmd and equipStrongest.hotbarEquip and equipStrongest.hotbarUnequip
end

function getToolInBackpack(slotId)
	local backpack = LP and LP:FindFirstChild("Backpack")
	if not backpack then
		return nil
	end
	for _, child in backpack:GetChildren() do
		if child:IsA("Tool") and slotIdMatches(child:GetAttribute("SlotId"), slotId) then
			return child
		end
	end
	return nil
end

function getToolAnywhere(slotId)
	local tool = getToolInBackpack(slotId)
	if tool then
		return tool
	end
	local character = LP and LP.Character
	if character then
		for _, child in character:GetChildren() do
			if child:IsA("Tool") and slotIdMatches(child:GetAttribute("SlotId"), slotId) then
				return child
			end
		end
	end
	return nil
end

function waitForToolInBackpack(slotId, timeout)
	local deadline = os.clock() + (timeout or 1)
	while os.clock() < deadline do
		local tool = getToolInBackpack(slotId)
		if tool then
			return tool
		end
		task.wait(0.05)
	end
	return getToolInBackpack(slotId)
end

function collectSlotsFromBackpack()
	local slots, seen = {}, {}
	for _, parent in { LP:FindFirstChild("Backpack"), LP.Character } do
		if parent then
			for _, child in parent:GetChildren() do
				if child:IsA("Tool") and isWeaponTool(child) then
					local slotId = child:GetAttribute("SlotId")
					if slotId and not seen[tostring(slotId)] then
						seen[tostring(slotId)] = true
						table.insert(slots, {
							Id = slotId,
							Item = { Name = child.Name, Rarity = child:GetAttribute("Rarity") },
						})
					end
				end
			end
		end
	end
	return slots
end

function pickStrongest(slots)
	local bestSlot, bestStrength = nil, -1
	for _, slot in slots do
		local s = getToolStrength(slot)
		if s > bestStrength then
			bestStrength = s
			bestSlot = slot
		end
	end
	return bestSlot, bestStrength
end

function findStrongestFromInventory(inventory)
	local bestSlot, bestStrength = nil, -1
	for _, itemSlot in inventory:GetItemSlots() do
		local item = itemSlot.Item
		if item and WEAPON_SUBTYPES[getWeaponSubtype(item.Name)] then
			local s = getToolStrength(itemSlot)
			if s > bestStrength then
				bestStrength = s
				bestSlot = itemSlot
			end
		end
	end
	return bestSlot, bestStrength
end

function findWeakestHotbarWeapon(inventory)
	local weakest, weakestStrength = nil, math.huge
	for _, itemSlot in inventory:GetHotbarItems() do
		if itemSlot.Item.Name ~= "DeleteTool" and WEAPON_SUBTYPES[getWeaponSubtype(itemSlot.Item.Name)] then
			local s = getToolStrength(itemSlot)
			if s < weakestStrength then
				weakestStrength = s
				weakest = itemSlot
			end
		end
	end
	if weakest then
		return weakest
	end
	for _, itemSlot in inventory:GetHotbarItems() do
		if itemSlot.Item.Name ~= "DeleteTool" then
			return itemSlot
		end
	end
	return nil
end

function ensureInHotbar(inventory, slotId)
	if inventory:IsItemInHotbar(slotId) and getToolInBackpack(slotId) then
		return true
	end

	local ok
	if inventory:GetHotbarCount() < inventory:GetHotbarCapacity() then
		ok = equipStrongest.invCmd.EquipItem:InvokeServer(slotId)
	else
		local swap = findWeakestHotbarWeapon(inventory)
		ok = swap and equipStrongest.invCmd.SwapItemInHotbar:InvokeServer(swap.Id, slotId)
	end
	if not ok then
		return false
	end
	return waitForToolInBackpack(slotId, 0.8) ~= nil
end

function forceToBackpack(slotId)
	if not equipStrongest.hotbarUnavailable then
		local hc = findHotbarClient()
		if hc then
			local equipped = hc:GetEquippedSlot()
			if equipped and slotIdMatches(equipped.Id, slotId) then
				return getToolInBackpack(slotId) or getToolAnywhere(slotId)
			end
			if equipped then
				pcall(function()
					hc:Unequip()
				end)
				task.wait(0.03)
			end
		end
	end

	local humanoid = LP.Character and LP.Character:FindFirstChildOfClass("Humanoid")
	if humanoid then
		humanoid:UnequipTools()
	end

	return waitForToolInBackpack(slotId, 0.25)
end

function waitForPlaying(maxWait)
	if LP:GetAttribute("GameState") == "Playing" then
		return true
	end
	local deadline = os.clock() + (maxWait or 5)
	while os.clock() < deadline do
		if LP:GetAttribute("GameState") == "Playing" then
			return true
		end
		task.wait(0.05)
	end
	return LP:GetAttribute("GameState") == "Playing"
end

function buildItemSlot(slotId, inventory)
	if inventory then
		local ok, slot = pcall(function()
			return inventory:GetItemSlot(slotId)
		end)
		if ok and slot then
			return slot
		end
	end
	local tool = getToolAnywhere(slotId)
	if not tool then
		return nil
	end
	return {
		Id = slotId,
		Item = { Name = tool.Name, Rarity = tool:GetAttribute("Rarity") or 1 },
	}
end

function manualDoEquip(hc, slotId, inventory)
	local slot = buildItemSlot(slotId, inventory)
	if not slot then
		warnLog("Equip -> invalid slot for manual equip")
		return false
	end

	if hc and hc.GetEquippedSlot then
		local current = hc:GetEquippedSlot()
		if current and not slotIdMatches(current.Id, slotId) then
			pcall(function()
				hc:Unequip()
			end)
			task.wait(0.05)
		end
	end

	if not forceToBackpack(slotId) then
		warnLog("Equip -> tool is not in the backpack")
		return false
	end

	local tool = getToolInBackpack(slotId)
	if not tool then
		return false
	end

	local humanoid = LP.Character and LP.Character:FindFirstChildOfClass("Humanoid")
	if not humanoid then
		return false
	end

	humanoid:EquipTool(tool)

	if hc and hc.Equipped and type(hc.Equipped.Fire) == "function" then
		pcall(function()
			hc.Equipped:Fire(slot, tool)
		end)
		log("Equip → sinal Equipped disparado manualmente")
	end

	pcall(function()
		equipStrongest.hotbarEquip:InvokeServer(slotId)
	end)

	if hc and hc.GetEquippedSlot then
		local equipped = hc:GetEquippedSlot()
		if equipped and slotIdMatches(equipped.Id, slotId) then
			return true
		end
	end

	return LP.Character and LP.Character:FindFirstChild(tool.Name) ~= nil
end

function gameEquip(slotId, inventory)
	if not waitForPlaying(3) then
		warnLog("Equip -> GameState is not Playing")
		return false
	end

	if equipStrongest.hotbarUnavailable then
		log("Equip -> hotbar unavailable, using fallback method")
		return manualDoEquip(nil, slotId, inventory)
	end

	local hc = findHotbarClient()
	if not hc then
		task.wait(0.12)
		hc = findHotbarClient()
	end
	if not hc then
		equipStrongest.hotbarUnavailable = true
		log("Equip -> hotbar unavailable, using fallback method")
		return manualDoEquip(nil, slotId, inventory)
	end

	if hc.GetEquippedSlot then
		local current = hc:GetEquippedSlot()
		if current and slotIdMatches(current.Id, slotId) then
			log("Equip -> already equipped via HotbarClient")
			return true
		end
		if current then
			pcall(function()
				hc:Unequip()
			end)
			task.wait(0.03)
		end
	end

	if not getToolAnywhere(slotId) then
		warnLog("Equip -> tool not found")
		return false
	end

	if not forceToBackpack(slotId) then
		forceToBackpack(slotId)
	end

	for attempt = 1, 2 do
		if not getToolInBackpack(slotId) then
			forceToBackpack(slotId)
		end

		pcall(function()
			hc:Equip(slotId)
		end)

		if hc.GetEquippedSlot then
			local equipped = hc:GetEquippedSlot()
			if equipped and slotIdMatches(equipped.Id, slotId) then
				log("Equip → cliente reconheceu via HotbarClient (tentativa " .. attempt .. ")")
				return true
			end
		end

		task.wait(0.03)
	end

	log("Equip → HotbarClient:Equip falhou, usando fallback manual")
	return manualDoEquip(hc, slotId, inventory)
end

function equipStrongestTool()
	local t0 = os.clock()
	log("Equip -> searching for strongest weapon...")

	if not getEquipNetwork() then
		warnLog("Equip -> Network not found")
		return false
	end

	local strongestSlot, strength
	local inventory = findInventoryObject()

	if inventory then
		strongestSlot, strength = findStrongestFromInventory(inventory)
	end

	if not strongestSlot then
		local bpSlots = collectSlotsFromBackpack()
		strongestSlot, strength = pickStrongest(bpSlots)
		log(("Equip -> backpack: %d weapons"):format(#bpSlots))
	elseif inventory then
		log(("Equip -> inventory: %d slots"):format(#inventory:GetItemSlots()))
	end

	if not strongestSlot then
		local deadline = os.clock() + 0.4
		while os.clock() < deadline do
			inventory = findInventoryObject()
			if inventory then
				strongestSlot, strength = findStrongestFromInventory(inventory)
				if strongestSlot then
					break
				end
			end
			local bpSlots = collectSlotsFromBackpack()
			if #bpSlots > 0 then
				strongestSlot, strength = pickStrongest(bpSlots)
				break
			end
			task.wait(0.05)
		end
	end

	if not strongestSlot then
		warnLog("Equip -> no weapon found")
		return false
	end

	log(("Equip -> weapon: %s (strength %.1f)"):format(strongestSlot.Item.Name, strength))

	if inventory and not inventory:IsItemInHotbar(strongestSlot.Id) then
		log("Equip → adicionando na hotbar...")
		if not ensureInHotbar(inventory, strongestSlot.Id) then
			if not getToolInBackpack(strongestSlot.Id) then
				warnLog("Equip → falha na hotbar")
				return false
			end
			log("Equip → tool na backpack mesmo sem confirmar hotbar")
		end
	elseif not getToolInBackpack(strongestSlot.Id) and not getToolAnywhere(strongestSlot.Id) then
		waitForToolInBackpack(strongestSlot.Id, 0.5)
	end

	if gameEquip(strongestSlot.Id, inventory) then
		log(("Equip -> %s equipped in %.2fs"):format(strongestSlot.Item.Name, os.clock() - t0))
		return true
	end

	return false
end

function equipStrongestOnRespawn(char)
	if not CONFIG.AutoEquipStrongestOnRespawn or not LP then
		return false
	end

	while state.equipInProgress do
		task.wait(0.05)
	end

	equipStrongest.hotbarUnavailable = false
	state.equipInProgress = true
	if CONFIG.AutoFarmEnabled then
		state.farmStatus = "equipping weapon..."
	end
	local ok, result = pcall(function()
		if not char or not char.Parent then
			char = LP.Character or LP.CharacterAdded:Wait()
		end

		pcall(function()
			LP:WaitForChild("ClientTagData", 20)
		end)
		char:WaitForChild("Humanoid", 15)
		waitForPlaying(5)
		task.wait(0.15)

		return equipStrongestTool()
	end)

	state.equipInProgress = false

	if not ok then
		warnLog("Equip → erro: " .. tostring(result))
		return false
	end

	return result == true
end

function canSwing(character)
	if not CONFIG.BypassBlock and character:GetAttribute("IsBlocking") then
		return false
	end
	if character:GetAttribute("BlockPercentage") ~= nil then
		return false
	end
	return true
end

function shouldUseMeleeHijack()
	return CONFIG.MeleeEnabled == true and CONFIG.AutoSwing == true
end

function cancelActiveMeleeHijack()
	local cancel = state.meleeSwingCancel
	state.meleeSwingCancel = nil
	state.swinging = false
	if cancel then
		pcall(cancel)
	end
end

function setMeleeHijackEnabled(enabled)
	CONFIG.MeleeEnabled = enabled == true
	if not shouldUseMeleeHijack() then
		cancelActiveMeleeHijack()
	end
end

function setAutoSwingEnabled(enabled)
	CONFIG.AutoSwing = enabled == true
	if not shouldUseMeleeHijack() then
		cancelActiveMeleeHijack()
	end
end

function newTicket(part, forcedType)
	local model = part.Parent
	if model and model.Name == "Head" and model:IsA("Model") then
		model = model.Parent
	end
	if model and model:IsA("Model") then
		if forcedType == "Resource" or hasTag(model, "GatherableMaterial") then
			return { type = "Resource", position = part.Position, target = model }
		end
		if forcedType == "Breakable" or hasTag(model, "Breakable") then
			return { type = "Breakable", position = part.Position, target = model }
		end
		if hasTag(model, "NPC") or hasTag(model, "PlayerCharacter") then
			return { type = "CharacterModel", position = part.Position, target = model, bodyPart = 1 }
		end
	end
	return { type = "Part", position = part.Position, target = part }
end

function modelFromTagged(tags)
	local out = {}
	local seen = {}
	for _, tag in tags do
		for _, inst in CollectionService:GetTagged(tag) do
			if inst:IsA("Model") and not seen[inst] then
				seen[inst] = true
				table.insert(out, inst)
			end
		end
	end
	return out
end

function distanceTo(model)
	local char = getCharacter()
	if not char then return math.huge end
	local part = model.PrimaryPart or model:FindFirstChildWhichIsA("BasePart")
	if not part then return math.huge end
	return (char.PrimaryPart.Position - part.Position).Magnitude
end

function getModelPosition(model)
	local part = model.PrimaryPart or model:FindFirstChildWhichIsA("BasePart")
	if part then return part.Position end
end

function isAliveNPC(model)
	if not model or not model:IsA("Model") then return false end
	if not hasTag(model, "NPC") then return false end
	local hum = model:FindFirstChildOfClass("Humanoid")
	if hum and hum.Health <= 0 then return false end
	local part = model.PrimaryPart or model:FindFirstChildWhichIsA("BasePart")
	return part ~= nil
end

function getAliveNPCs()
	local out = {}
	for _, model in CollectionService:GetTagged("NPC") do
		if isAliveNPC(model) then
			table.insert(out, model)
		end
	end
	return out
end

function countNPCsNear(position, radius)
	if not position then
		return 0
	end
	local n = 0
	local radiusSq = radius * radius
	for _, model in getAliveNPCs() do
		local pos = getModelPosition(model)
		if pos then
			local delta = pos - position
			if delta.X * delta.X + delta.Y * delta.Y + delta.Z * delta.Z <= radiusSq then
				n += 1
			end
		end
	end
	return n
end

-- ============================================================
-- AUTO FARM (NPCSpawners → Locations → raycast TP → farm)
-- ============================================================

function findWorkspaceFolder(folderName)
	local folder = workspace:FindFirstChild(folderName)
	if folder then
		return folder
	end
	return workspace:FindFirstChild(folderName, true)
end

function getSpawnPartPosition(part)
	if not part or not part:IsA("BasePart") then
		return nil
	end
	return part.Position
end

function farmRaycastGround(origin)
	local params = RaycastParams.new()
	params.FilterType = Enum.RaycastFilterType.Exclude
	local char = getCharacter()
	if char then
		params.FilterDescendantsInstances = { char }
	end
	return workspace:Raycast(origin, Vector3.new(0, -CONFIG.FarmRaycastDistance, 0), params)
end

function farmTeleportToPosition(worldPos)
	local char = getCharacter()
	if not char or not char.PrimaryPart or not worldPos then
		return false
	end

	local root = char.PrimaryPart
	local origin = worldPos + Vector3.new(0, CONFIG.FarmRaycastHeightOffset, 0)
	local hit = farmRaycastGround(origin)
	local targetPos

	if hit then
		targetPos = hit.Position + Vector3.new(0, CONFIG.FarmTeleportHeightOffset, 0)
	else
		targetPos = worldPos + Vector3.new(0, CONFIG.FarmTeleportHeightOffset, 0)
		warnLog(("Farm raycast sem hit @ %.0f, %.0f, %.0f"):format(worldPos.X, worldPos.Y, worldPos.Z))
	end

	root.Anchored = true
	pcall(function()
		char:PivotTo(CFrame.new(targetPos))
	end)
	root.CFrame = CFrame.new(targetPos)
	root.AssemblyLinearVelocity = Vector3.zero
	root.AssemblyAngularVelocity = Vector3.zero
	root.Anchored = false

	return true
end

function farmTeleportToPart(part)
	local pos = getSpawnPartPosition(part)
	if not pos then
		return false
	end
	return farmTeleportToPosition(pos)
end

function isNpcSpawnerSpawnPart(inst)
	return inst
		and inst:IsA("BasePart")
		and string.find(inst.Name, "Spawn") ~= nil
end

function collectNamedSpawnParts(root)
	local parts = {}
	if not root then
		return parts
	end

	for _, desc in root:GetDescendants() do
		if desc:IsA("BasePart") and desc.Name == "Spawn" then
			table.insert(parts, desc)
		end
	end

	table.sort(parts, function(a, b)
		return a:GetFullName() < b:GetFullName()
	end)

	return parts
end

function collectNpcSpawnerSpawnParts(locationFolder)
	local parts = {}
	if not locationFolder then
		return parts
	end

	for _, child in locationFolder:GetChildren() do
		if isNpcSpawnerSpawnPart(child) then
			table.insert(parts, child)
		end
	end

	for _, desc in locationFolder:GetDescendants() do
		if isNpcSpawnerSpawnPart(desc) then
			local seen = false
			for _, existing in parts do
				if existing == desc then
					seen = true
					break
				end
			end
			if not seen then
				table.insert(parts, desc)
			end
		end
	end

	table.sort(parts, function(a, b)
		return a:GetFullName() < b:GetFullName()
	end)

	return parts
end

function discoverFarmLocations()
	local locations = {}
	local spawnersFolder = findWorkspaceFolder(CONFIG.FarmNpcSpawnersFolder)
	if not spawnersFolder then
		warnLog("Farm -> folder not found: " .. CONFIG.FarmNpcSpawnersFolder)
		return locations
	end

	for _, child in spawnersFolder:GetChildren() do
		if child:IsA("Folder") or child:IsA("Model") then
			table.insert(locations, child.Name)
		end
	end

	table.sort(locations)
	return locations
end

function isFarmLocationEnabled(locationName)
	local value = CONFIG.FarmLocationEnabled and CONFIG.FarmLocationEnabled[locationName]
	return value ~= false
end

function setFarmLocationEnabled(locationName, enabled)
	CONFIG.FarmLocationEnabled = CONFIG.FarmLocationEnabled or {}
	CONFIG.FarmLocationEnabled[locationName] = enabled == true
end

function getEnabledFarmLocations(locations)
	local enabled = {}
	for _, locationName in locations do
		if isFarmLocationEnabled(locationName) then
			table.insert(enabled, locationName)
		end
	end
	return enabled
end

function scanFarmLocations(force)
	if not force and state.farmLocationsCached and #state.farmLocations > 0 then
		return state.farmLocations
	end

	state.farmLocations = discoverFarmLocations()
	state.farmLocationsCached = true
	CONFIG.FarmLocationEnabled = CONFIG.FarmLocationEnabled or {}
	for _, locationName in state.farmLocations do
		if CONFIG.FarmLocationEnabled[locationName] == nil then
			CONFIG.FarmLocationEnabled[locationName] = true
		end
	end

	if #state.farmLocations > 0 then
		log(("Farm -> %d locations in %s"):format(#state.farmLocations, CONFIG.FarmNpcSpawnersFolder))
	else
		log("Farm -> no locations in " .. CONFIG.FarmNpcSpawnersFolder)
	end

	return state.farmLocations
end

function getLocationInstance(locationName)
	local folder = findWorkspaceFolder(CONFIG.FarmLocationsFolder)
	if not folder then
		return nil
	end
	return folder:FindFirstChild(locationName)
end

function getNpcSpawnerFolder(locationName)
	local folder = findWorkspaceFolder(CONFIG.FarmNpcSpawnersFolder)
	if not folder then
		return nil
	end
	return folder:FindFirstChild(locationName)
end

function countNPCsNearPosition(position, radius)
	if not position then
		return 0
	end

	local n = 0
	local radiusSq = radius * radius
	for _, model in getAliveNPCs() do
		local pos = getModelPosition(model)
		if pos then
			local delta = pos - position
			if delta.X * delta.X + delta.Y * delta.Y + delta.Z * delta.Z <= radiusSq then
				n += 1
			end
		end
	end
	return n
end

function countNPCsNearPlayer()
	local char = getCharacter()
	if not char or not char.PrimaryPart then
		return 0
	end
	return countNPCsNearPosition(char.PrimaryPart.Position, CONFIG.FarmZoneRadius)
end

function findNumericValueByNames(root, names)
	if not root then return nil end
	local wanted = {}
	for _, name in names do
		wanted[string.lower(name)] = true
	end

	for _, desc in root:GetDescendants() do
		if wanted[string.lower(desc.Name)] then
			if desc:IsA("IntValue") or desc:IsA("NumberValue") then
				return desc.Value
			end
			local value = desc:GetAttribute("Value")
			if type(value) == "number" then
				return value
			end
		end
	end

	for _, name in names do
		local attr = root:GetAttribute(name)
		if type(attr) == "number" then
			return attr
		end
	end

	return nil
end

function safeRecordGet(record, key)
	if not record or type(record.Get) ~= "function" then
		return nil
	end

	local ok, value = pcall(function()
		return record:Get(key)
	end)
	if ok then
		return value
	end
	return nil
end

function readFarmStatSnapshot()
	local manager = findLoadedSessionManager()
	if manager then
		local ok, slot = pcall(manager.GetSlot, LP)
		if ok and slot then
			local coins = safeRecordGet(slot, "Coins")
				or safeRecordGet(slot, "Money")
				or safeRecordGet(slot, "Cash")
				or safeRecordGet(slot, "Gold")
			local experience = safeRecordGet(slot, "Experience")
				or safeRecordGet(slot, "XP")
				or safeRecordGet(slot, "Exp")
			local level = safeRecordGet(slot, "Level")
				or safeRecordGet(slot, "Lvl")
			if type(coins) == "number" or type(experience) == "number" or type(level) == "number" then
				return {
					currency = coins,
					xp = experience,
					level = level,
				}
			end
		end
	end

	local leaderstats = LP and LP:FindFirstChild("leaderstats")
	return {
		currency = findNumericValueByNames(leaderstats, { "Coins", "Money", "Cash", "Gold", "Currency" })
			or findNumericValueByNames(LP, { "Coins", "Money", "Cash", "Gold", "Currency" }),
		xp = findNumericValueByNames(leaderstats, { "XP", "Exp", "Experience" })
			or findNumericValueByNames(LP, { "XP", "Exp", "Experience" }),
		level = findNumericValueByNames(leaderstats, { "Level", "Lvl" })
			or findNumericValueByNames(LP, { "Level", "Lvl" }),
	}
end

function startFarmStats()
	state.farmStatsStartedAt = os.clock()
	state.farmStatsBaseline = readFarmStatSnapshot()
end

function formatDuration(seconds)
	seconds = math.max(0, math.floor(seconds or 0))
	local hours = math.floor(seconds / 3600)
	local minutes = math.floor((seconds % 3600) / 60)
	local secs = seconds % 60
	if hours > 0 then
		return ("%02d:%02d:%02d"):format(hours, minutes, secs)
	end
	return ("%02d:%02d"):format(minutes, secs)
end

function formatDelta(current, baseline)
	if type(current) ~= "number" or type(baseline) ~= "number" then
		return "N/A"
	end
	local delta = current - baseline
	if delta >= 0 then
		return "+" .. tostring(delta)
	end
	return tostring(delta)
end

function getFarmStatsText()
	local elapsed = state.farmStatsStartedAt and (os.clock() - state.farmStatsStartedAt) or 0
	local baseline = state.farmStatsBaseline or readFarmStatSnapshot()
	local current = readFarmStatSnapshot()

	return table.concat({
		"Elapsed: " .. formatDuration(elapsed),
		"Coins gained: " .. formatDelta(current.currency, baseline.currency),
		"XP gained: " .. formatDelta(current.xp, baseline.xp),
		"Levels gained: " .. formatDelta(current.level, baseline.level),
	}, "\n")
end

function applyFarmMeleePreset(enable)
	if enable and not CONFIG.FarmAutoMelee then
		return
	end

	if enable then
		if not state.farmMeleeSaved then
			state.farmMeleeSaved = {
				melee = CONFIG.MeleeEnabled,
				swing = CONFIG.AutoSwing,
				npcs = CONFIG.TargetNPCs,
				players = CONFIG.TargetPlayers,
				tool = CONFIG.RequireMeleeTool,
			}
		end
		setMeleeHijackEnabled(true)
		setAutoSwingEnabled(true)
		CONFIG.TargetNPCs = true
		CONFIG.TargetPlayers = false
		CONFIG.RequireMeleeTool = true
		releaseFarmMouse()
	else
		local saved = state.farmMeleeSaved
		if saved then
			CONFIG.MeleeEnabled = saved.melee
			CONFIG.AutoSwing = saved.swing
			CONFIG.TargetNPCs = saved.npcs
			CONFIG.TargetPlayers = saved.players
			CONFIG.RequireMeleeTool = saved.tool
			state.farmMeleeSaved = nil
		end
		if not shouldUseMeleeHijack() then
			cancelActiveMeleeHijack()
		end
		restoreFarmMouse()
	end
end

function refreshFarmUi()
	local now = tick()
	if _G.PentestUI and _G.PentestUI.Refresh and now - state.farmLastUiRefresh >= 1 then
		state.farmLastUiRefresh = now
		_G.PentestUI.Refresh()
	end
end

function waitWhileFarmBlocked()
	while CONFIG.AutoFarmEnabled and (state.farmRespawnPending or state.equipInProgress) do
		if state.equipInProgress then
			state.farmStatus = "equipping weapon..."
		else
			state.farmStatus = "dead -> waiting for respawn"
		end
		refreshFarmUi()
		task.wait(0.05)
	end
end

function farmSleep(seconds)
	local deadline = os.clock() + seconds
	while os.clock() < deadline do
		waitWhileFarmBlocked()
		if not CONFIG.AutoFarmEnabled then
			return false
		end
		task.wait(math.min(0.1, deadline - os.clock()))
	end
	return true
end

function farmWaitUntilClear()
	local started = tick()
	local emptySince = nil
	local sawNPCs = false

	while CONFIG.AutoFarmEnabled do
		waitWhileFarmBlocked()
		if not CONFIG.AutoFarmEnabled then
			return false
		end

		local elapsed = tick() - started
		local near = countNPCsNearPlayer()

		if near > CONFIG.FarmClearThreshold then
			sawNPCs = true
			emptySince = nil
		end

		if sawNPCs and elapsed >= CONFIG.FarmMinFarmTime and near <= CONFIG.FarmClearThreshold then
			if not emptySince then
				emptySince = tick()
			elseif tick() - emptySince >= CONFIG.FarmClearConfirmTime then
				return true
			end
		else
			emptySince = nil
		end

		if elapsed >= CONFIG.FarmMaxFarmTime then
			if sawNPCs then
				warnLog(("Farm timeout with NPCs seen -> skipping after %.0fs"):format(elapsed))
			else
				warnLog(("Farm timeout without NPCs -> skipping after %.0fs"):format(elapsed))
			end
			return true
		end

		releaseFarmMouse()
		state.farmStatus = ("farm | %d npc | %.0fs%s"):format(
			near,
			elapsed,
			sawNPCs and "" or " | waiting for mobs"
		)
		farmSleep(0.4)
	end

	return false
end

function runFarmLocation(locationName)
	waitWhileFarmBlocked()
	if not CONFIG.AutoFarmEnabled or not isFarmLocationEnabled(locationName) then
		return
	end

	local locationInst = getLocationInstance(locationName)
	if not locationInst then
		warnLog("Farm -> location not found in " .. CONFIG.FarmLocationsFolder .. ": " .. locationName)
		return
	end

	local locationSpawns = collectNamedSpawnParts(locationInst)
	if #locationSpawns == 0 then
		warnLog("Farm -> no Spawn part in " .. locationName)
		return
	end

	state.farmActiveLocation = locationName
	log(("Farm -> activating %s (%d Spawn)"):format(locationName, #locationSpawns))

	for i, spawnPart in locationSpawns do
		waitWhileFarmBlocked()
		if not CONFIG.AutoFarmEnabled or not isFarmLocationEnabled(locationName) then
			return
		end
		state.farmStatus = ("activate %s | Spawn %d/%d"):format(locationName, i, #locationSpawns)
		refreshFarmUi()
		if farmTeleportToPart(spawnPart) then
			log(("Farm TP location -> %s [%s]"):format(locationName, spawnPart:GetFullName()))
		end
		if not farmSleep(0.5) then
			return
		end
	end

	state.farmStatus = ("waiting for spawn -> %s (%.1fs)"):format(locationName, CONFIG.FarmSpawnWaitTime)
	refreshFarmUi()
	if not farmSleep(CONFIG.FarmSpawnWaitTime) then
		return
	end

	if not CONFIG.AutoFarmEnabled then
		return
	end

	local npcFolder = getNpcSpawnerFolder(locationName)
	if not npcFolder then
		warnLog("Farm -> missing NPCSpawners folder: " .. locationName)
		return
	end

	local npcSpawns = collectNpcSpawnerSpawnParts(npcFolder)
	if #npcSpawns == 0 then
		warnLog("Farm -> no Spawn* in " .. CONFIG.FarmNpcSpawnersFolder .. "/" .. locationName)
		return
	end

	log(("Farm -> %d spawners in %s"):format(#npcSpawns, locationName))

	for i, spawnPart in npcSpawns do
		waitWhileFarmBlocked()
		if not CONFIG.AutoFarmEnabled or not isFarmLocationEnabled(locationName) then
			return
		end

		state.farmSpawnIndex = i
		state.farmStatus = ("tp spawner %s | %d/%d"):format(locationName, i, #npcSpawns)
		refreshFarmUi()

		if not farmTeleportToPart(spawnPart) then
			warnLog("Farm TP failed -> " .. spawnPart:GetFullName())
			continue
		end

		log(("Farm TP spawner -> %s"):format(spawnPart:GetFullName()))
		state.farmStatus = ("waiting for mobs %s | %d/%d (%.1fs)"):format(
			locationName, i, #npcSpawns, CONFIG.FarmPostTeleportWait
		)
		refreshFarmUi()
		if not farmSleep(CONFIG.FarmPostTeleportWait) then
			return
		end
		releaseFarmMouse()

		state.farmStatus = ("farm %s | spawner %d/%d"):format(locationName, i, #npcSpawns)
		if not farmWaitUntilClear() then
			return
		end

		log(("Farm clear -> %s spawner %d/%d"):format(locationName, i, #npcSpawns))
	end
end

function runAutoFarmLoop()
	state.farmLoopRunning = true
	waitWhileFarmBlocked()
	if CONFIG.AutoEquipStrongestOnRespawn then
		local char = getCharacter()
		if char and not getMeleeTool(char) then
			equipStrongestOnRespawn(char)
			waitWhileFarmBlocked()
		end
	end
	applyFarmMeleePreset(true)
	releaseFarmMouse()
	scanFarmLocations(true)

	while CONFIG.AutoFarmEnabled do
		waitWhileFarmBlocked()
		if not CONFIG.AutoFarmEnabled then
			break
		end

		local locations = scanFarmLocations(false)
		local enabledLocations = getEnabledFarmLocations(locations)
		if #locations == 0 then
			state.farmStatus = "no locations"
			refreshFarmUi()
			if not farmSleep(2) then
				break
			end
			continue
		end
		if #enabledLocations == 0 then
			state.farmStatus = "all locations disabled"
			refreshFarmUi()
			if not farmSleep(2) then
				break
			end
			continue
		end

		for index, locationName in enabledLocations do
			waitWhileFarmBlocked()
			if not CONFIG.AutoFarmEnabled then
				break
			end
			state.farmLocationIndex = index
			runFarmLocation(locationName)
		end
	end

	state.farmLoopRunning = false
	state.farmStatus = "idle"
	state.farmActiveLocation = nil
	state.farmSpawnIndex = 0
	applyFarmMeleePreset(false)
	refreshFarmUi()
end

function getFarmRespawnRemote()
	if state.farmRespawnRemote then
		return state.farmRespawnRemote
	end
	local ok, remote = pcall(function()
		return ReplicatedStorage:WaitForChild("Network", 15)
			:WaitForChild("Revive", 15)
			:WaitForChild("Respawn", 15)
	end)
	if ok and remote and remote:IsA("RemoteEvent") then
		state.farmRespawnRemote = remote
	end
	return state.farmRespawnRemote
end

function clearFarmDeathHooks()
	for _, conn in state.farmDeathConns do
		pcall(function()
			conn:Disconnect()
		end)
	end
	table.clear(state.farmDeathConns)
end

function requestFarmRespawn()
	local remote = getFarmRespawnRemote()
	if not remote then
		warnLog("Auto respawn: Revive.Respawn remote not found")
		return false
	end
	for _, delay in CONFIG.FarmRespawnDelays do
		task.delay(delay, function()
			if not CONFIG.AutoFarmEnabled or not CONFIG.FarmAutoRespawn or not state.farmRespawnPending then
				return
			end
			pcall(function()
				remote:FireServer()
			end)
		end)
	end
	return true
end

function onFarmPlayerDied()
	if not CONFIG.AutoFarmEnabled or not CONFIG.FarmAutoRespawn or state.farmDeathHandled then
		return
	end

	state.farmDeathHandled = true
	state.farmRespawnPending = true
	state.farmStatus = "dead -> respawn"
	log("Auto Farm -> death detected, automatic respawn")
	requestFarmRespawn()
end

function setupFarmAutoRespawn(char)
	clearFarmDeathHooks()
	if not CONFIG.AutoFarmEnabled or not CONFIG.FarmAutoRespawn or not char then
		return
	end

	state.farmDeathHandled = false

	local hum = char:FindFirstChildOfClass("Humanoid")
	if not hum then
		hum = char:WaitForChild("Humanoid", 10)
	end
	if not hum then
		return
	end

	table.insert(state.farmDeathConns, hum.Died:Connect(onFarmPlayerDied))
	table.insert(state.farmDeathConns, hum.HealthChanged:Connect(function(hp)
		if hp <= 0 then
			onFarmPlayerDied()
		end
	end))
end

function resumeFarmAfterRespawn(char)
	if not CONFIG.AutoFarmEnabled or not state.farmRespawnPending then
		setupFarmAutoRespawn(char)
		return
	end

	while state.equipInProgress do
		state.farmStatus = "equipping weapon..."
		refreshFarmUi()
		task.wait(0.05)
	end

	state.farmRespawnPending = false
	state.farmDeathHandled = false
	applyFarmMeleePreset(true)
	setupFarmAutoRespawn(char)

	if char and not char.Parent then
		char = LP.CharacterAdded:Wait()
	end
	if char then
		char:WaitForChild("Humanoid", 20)
	end

	if not CONFIG.AutoFarmEnabled then
		return
	end

	if not state.farmLoopRunning then
		state.farmThread = task.spawn(runAutoFarmLoop)
	end

	log("Auto Farm resumed after respawn")
end

function startAutoFarm()
	if CONFIG.AutoFarmEnabled and state.farmLoopRunning then
		return
	end

	CONFIG.AutoFarmEnabled = true
	state.farmLocationIndex = 1
	state.farmSpawnIndex = 0
	state.farmStatus = "starting"
	state.farmLocationsCached = false
	startFarmStats()

	setupFarmAutoRespawn(getCharacter())

	if state.farmThread then
		task.cancel(state.farmThread)
		state.farmThread = nil
	end

	state.farmThread = task.spawn(runAutoFarmLoop)
	log("Auto Farm enabled (NPCSpawners -> Locations.Spawn -> farm spawners)")
end

function stopAutoFarm()
	CONFIG.AutoFarmEnabled = false
	state.farmRespawnPending = false
	state.farmDeathHandled = false
	state.farmActiveLocation = nil
	state.farmSpawnIndex = 0
	state.farmStatus = "idle"

	if state.farmThread then
		task.cancel(state.farmThread)
		state.farmThread = nil
	end

	clearFarmDeathHooks()
	applyFarmMeleePreset(false)
	restoreFarmMouse()
	state.farmLocations = {}
	state.farmLocationsCached = false
	log("Auto Farm disabled")
end
-- ============================================================
-- REMOTE DISCOVERY
-- ============================================================

function scanRemotes(root, depth, out, path)
	depth = depth or 0
	path = path or ""
	if not root or depth > 7 then return end
	for _, ch in root:GetChildren() do
		local p = path == "" and ch.Name or path .. "." .. ch.Name
		if ch:IsA("RemoteFunction") or ch:IsA("RemoteEvent") or ch:IsA("UnreliableRemoteEvent") then
			table.insert(out, { path = p, class = ch.ClassName, inst = ch })
		else
			scanRemotes(ch, depth + 1, out, p)
		end
	end
end

function classifyRemote(path)
	local lower = string.lower(path)
	if string.find(lower, "melee") or string.find(lower, "swing") then
		return "melee"
	end
	if string.find(lower, "gather") or string.find(lower, "resource") or string.find(lower, "harvest") then
		return "gather"
	end
	if string.find(lower, "break") or string.find(lower, "destroy") then
		return "break"
	end
	if string.find(lower, "interact") or string.find(lower, "door") or string.find(lower, "use") or string.find(lower, "activate") then
		return "interact"
	end
	return "other"
end

function discoverRemotes()
	local rs = game:GetService("ReplicatedStorage")
	local network = rs:FindFirstChild("Network")
	state.remotes = {}

	if not network then
		warnLog("ReplicatedStorage.Network not found")
		return
	end

	scanRemotes(network, 0, state.remotes, "Network")

	local meleeSwing = network:FindFirstChild("Items")
		and network.Items:FindFirstChild("Melee")
		and network.Items.Melee:FindFirstChild("Swing")

	if meleeSwing then
		state.meleeNet = network.Items.Melee
	else
		for _, r in state.remotes do
			if r.inst.Name == "Swing" and classifyRemote(r.path) == "melee" then
				local parts = string.split(r.path, ".")
				local cursor = network
				for i = 2, #parts - 1 do
					cursor = cursor and cursor:FindFirstChild(parts[i])
				end
				if cursor then
					state.meleeNet = cursor
					break
				end
			end
		end
	end

	log(("Remotes: %d | MeleeNet: %s"):format(
		#state.remotes,
		state.meleeNet and "ok" or "not found"
	))

	for _, r in state.remotes do
		log(r.class .. " → " .. r.path)
	end
end

-- ============================================================
-- HIT DETECTION (MELEE)
-- ============================================================

local HitDetection = {}

function getMeleeDistanceRange()
	if CONFIG.MeleeDistanceRange and CONFIG.MeleeDistanceRange > 0 then
		return CONFIG.MeleeDistanceRange
	end
	return math.max(CONFIG.HitboxSize.X, CONFIG.HitboxSize.Y, CONFIG.HitboxSize.Z) * 0.5
end

function getModelHitPart(model)
	return model.PrimaryPart
		or model:FindFirstChild("HumanoidRootPart")
		or model:FindFirstChild("Head")
		or model:FindFirstChildWhichIsA("BasePart")
end

function collectMeleeModels()
	local models = {}
	local seen = {}
	local tags = { "NPC", "PlayerCharacter", "Breakable", "GatherableMaterial" }

	for _, tag in tags do
		for _, inst in CollectionService:GetTagged(tag) do
			local model = inst
			if not model:IsA("Model") then
				model = inst:FindFirstAncestorOfClass("Model")
			end
			if model and not seen[model] then
				seen[model] = true
				table.insert(models, model)
			end
		end
	end

	return models
end

function HitDetection.GetSwingTargets(rootCF, hitboxSize, overlapParams, hitModels, filterFn)
	local targets = {}
	local lookCF = CFrame.lookAlong(
		rootCF * Vector3.new(0, 0, -CONFIG.HitboxForwardOffset),
		rootCF.LookVector
	)
	for _, part in workspace:GetPartBoundsInBox(lookCF, hitboxSize, overlapParams) do
		local model = part.Parent
		if model and model:IsA("Model") and not hitModels[model] then
			if filterFn(model, part) then
				overlapParams:AddToFilter(model)
				hitModels[model] = true
				table.insert(targets, newTicket(part))
			end
		end
	end
	return targets
end

function HitDetection.GetDistanceTargets(rootPart, range, hitModels, filterFn)
	local targets = {}
	if not rootPart then return targets end

	local origin = rootPart.Position
	local ownCharacter = rootPart.Parent
	for _, model in collectMeleeModels() do
		if model ~= ownCharacter and not hitModels[model] then
			local part = getModelHitPart(model)
			local delta = part and (part.Position - origin)
			local flatDistance = delta and Vector3.new(delta.X, 0, delta.Z).Magnitude
			if part and flatDistance <= range and filterFn(model, part) then
				hitModels[model] = true
				table.insert(targets, newTicket(part))
			end
		end
	end

	return targets
end

function HitDetection.StartRecording(params)
	local elapsed = 0
	local window = math.clamp(params.Duration - params.WindDown, 0.1, 1)
	local root, overlap, camera, filterFn = params.RootPart, params.OverlapParams, params.Camera, params.FilterFn
	local seen = {}
	return coroutine.create(function()
		while elapsed < window do
			local cf = root.CFrame
			if camera and CONFIG.UseCameraAim then
				cf = CFrame.lookAlong(cf.Position, camera.CFrame.LookVector)
			end
			local targets = HitDetection.GetSwingTargets(cf, CONFIG.HitboxSize, overlap, seen, filterFn)
			if CONFIG.UseDistanceMeleeScan then
				for _, ticket in HitDetection.GetDistanceTargets(root, getMeleeDistanceRange(), seen, filterFn) do
					table.insert(targets, ticket)
				end
			end
			elapsed = elapsed + coroutine.yield(targets)
		end
	end)
end

function HitDetection.Swing(params, onHit)
	local recorder = HitDetection.StartRecording(params)
	local thread = task.spawn(function()
		task.wait(CONFIG.WindUp)
		while coroutine.status(recorder) ~= "dead" do
			local ok, targets = coroutine.resume(recorder, task.wait(CONFIG.ScanInterval))
			if targets == nil then break end
			if ok == false then error(debug.traceback(recorder, tostring(targets))) end
			if #targets > 0 then
				local batch = {}
				for i = 1, math.min(#targets, CONFIG.MaxTargetsPerBatch) do
					batch[i] = targets[i]
				end
				task.spawn(onHit, batch)
			end
		end
	end)
	return function()
		task.cancel(thread)
		task.cancel(recorder)
	end
end

-- ============================================================
-- CORE ACTIONS
-- ============================================================

function meleeFilter(model)
	if hasTag(model, "NPC") and CONFIG.TargetNPCs then return true end
	if hasTag(model, "PlayerCharacter") and CONFIG.TargetPlayers then return true end
	if hasTag(model, "Breakable") and CONFIG.TargetBreakables then return true end
	if hasTag(model, "GatherableMaterial") and CONFIG.TargetGatherables then return true end
	return false
end

function invokeMelee(batch)
	if not state.meleeNet or not state.meleeNet:FindFirstChild("Swing") then return end
	local char = getCharacter()
	if not char then return end
	pcall(function()
		state.meleeNet.Swing:InvokeServer(char, encode(batch))
	end)
end

function invokeMeleeHijack(batch)
	if not shouldUseMeleeHijack() then return end
	invokeMelee(batch)
end

function doMeleeSwing()
	if not shouldUseMeleeHijack() then
		cancelActiveMeleeHijack()
		return
	end
	if state.swinging then return end
	if tick() - state.lastMelee < CONFIG.MeleeCooldown then return end

	local character = getCharacter()
	if not character then return end
	if not canSwing(character) then return end
	if CONFIG.RequireMeleeTool and not getMeleeTool(character) then return end
	if not state.meleeNet then return end

	state.swinging = true
	state.lastMelee = tick()

	pcall(function()
		local humanoid = character:FindFirstChildOfClass("Humanoid")
		local tool = getMeleeTool(character)
		local rs = game:GetService("ReplicatedStorage")
		local folder = rs:FindFirstChild("Assets")
			and rs.Assets:FindFirstChild("Items")
			and rs.Assets.Items:FindFirstChild("Animations")
			and rs.Assets.Items.Animations:FindFirstChild("Melee")
		if humanoid and folder and tool then
			local typeFolder = folder:FindFirstChild(tool:GetAttribute("Type") or "OneHanded")
			local anim = typeFolder and (typeFolder:FindFirstChild("Swing1") or typeFolder:FindFirstChild("Swing2"))
			if anim and anim:IsA("Animation") then
				humanoid:LoadAnimation(anim):Play()
			end
		end
	end)

	local overlap = OverlapParams.new()
	overlap.FilterDescendantsInstances = { character }
	overlap.FilterType = Enum.RaycastFilterType.Exclude

	local cancel = HitDetection.Swing({
		RootPart = character.PrimaryPart,
		Camera = workspace.CurrentCamera,
		OverlapParams = overlap,
		Duration = CONFIG.Duration,
		WindDown = CONFIG.WindDown,
		FilterFn = meleeFilter,
	}, invokeMeleeHijack)
	state.meleeSwingCancel = cancel

	task.delay(CONFIG.SwingLockTime, function()
		if state.meleeSwingCancel == cancel then
			state.meleeSwingCancel = nil
		end
		state.swinging = false
		pcall(cancel)
	end)
end

function ticketsFromModels(models, forcedType, maxCount)
	local tickets = {}
	local char = getCharacter()
	if not char then return tickets end

	table.sort(models, function(a, b)
		return distanceTo(a) < distanceTo(b)
	end)

	for _, model in models do
		if #tickets >= maxCount then break end
		local part = model.PrimaryPart or model:FindFirstChildWhichIsA("BasePart")
		if part then
			table.insert(tickets, newTicket(part, forcedType))
		end
	end
	return tickets
end

function doGather()
	if not CONFIG.GatherEnabled then return end
	if tick() - state.lastGather < CONFIG.GatherCooldown then return end
	if not state.meleeNet then return end

	local models = modelFromTagged({ "GatherableMaterial" })
	local tickets = ticketsFromModels(models, "Resource", CONFIG.GatherMaxPerTick)
	if #tickets == 0 then return end

	state.lastGather = tick()
	invokeMelee(tickets)
	log("Gather -> " .. #tickets .. " targets")
end

function doBreak()
	if not CONFIG.BreakEnabled then return end
	if tick() - state.lastBreak < CONFIG.BreakCooldown then return end
	if not state.meleeNet then return end

	local models = modelFromTagged({ "Breakable" })
	local tickets = ticketsFromModels(models, "Breakable", CONFIG.BreakMaxPerTick)
	if #tickets == 0 then return end

	state.lastBreak = tick()
	invokeMelee(tickets)
	log("Break -> " .. #tickets .. " targets")
end

function doSpam()
	if not CONFIG.SpamEnabled then return end
	if not state.meleeNet then return end

	local char = getCharacter()
	if not char then return end

	local allModels = {}
	for _, tag in { "NPC", "PlayerCharacter", "GatherableMaterial", "Breakable" } do
		for _, m in CollectionService:GetTagged(tag) do
			if m:IsA("Model") then
				table.insert(allModels, m)
			end
		end
	end

	local tickets = ticketsFromModels(allModels, nil, CONFIG.MaxTargetsPerBatch)
	if #tickets == 0 then return end

	for i = 1, CONFIG.SpamParallel do
		task.spawn(function()
			pcall(function()
				state.meleeNet.Swing:InvokeServer(char, encode(tickets))
			end)
		end)
	end
end

-- ============================================================
-- AUTO BOWLING (BowlingStrikeHijack)
-- ============================================================

function bowlingLog(msg)
	log("[Bowling] " .. msg)
end

function bowlingIsInMinigame()
	if not state.bowlingClientTagData then return false end
	return hasTag(state.bowlingClientTagData, "InMinigame")
end

function getMeerkatBowling()
	local interiors = workspace:FindFirstChild("Interiors")
	if not interiors then return nil end
	return interiors:FindFirstChild("Meerkat Bowling")
end

function getBowlingLocalLane()
	local mb = getMeerkatBowling()
	if not mb then return nil end
	local lanes = mb:FindFirstChild("Minigame") and mb.Minigame:FindFirstChild("Lanes")
	if not lanes then return nil end
	for _, lane in lanes:GetChildren() do
		if lane:FindFirstChild("Spawn") then
			local spawn = lane.Spawn:FindFirstChild("Spawn")
			if spawn and LP.Character and LP.Character.PrimaryPart then
				local dist = (spawn.Position - LP.Character.PrimaryPart.Position).Magnitude
				if dist < 80 then
					return lane
				end
			end
		end
	end
	return lanes:FindFirstChild("Lane1")
end

function isBowlingObstacleModel(inst)
	return inst:IsA("Model") and (inst.Name == "Wall" or inst.Name == "MovingWall")
end

function clearBowlingObstacles()
	if not CONFIG.BowlingRemoveObstacles or not state.bowlingInMinigame then return end

	local mb = getMeerkatBowling()
	if not mb then return end

	for _, desc in mb:GetDescendants() do
		if isBowlingObstacleModel(desc) then
			desc:Destroy()
		elseif desc.Name == "Wall" and desc:IsA("BasePart") then
			desc.CanCollide = false
			desc.CanTouch = false
			desc.Transparency = 1
		end
	end
end

function knockBowlingPins(lane)
	lane = lane or getBowlingLocalLane()
	if not lane then return end

	for _, desc in lane:GetDescendants() do
		if desc.Name == "Pin" and desc:IsA("BasePart") then
			desc.Anchored = false
			desc.CanCollide = true
			desc.CFrame = desc.CFrame * CFrame.Angles(math.rad(85), 0, 0)
			desc.AssemblyLinearVelocity = Vector3.new(0, 0, -50)
			desc.AssemblyAngularVelocity = Vector3.new(15, 0, 0)
		end
	end
end

function findThrownBowlingBall()
	local char = LP.Character
	if not char or not char.PrimaryPart then return nil end

	local hrp = char.PrimaryPart
	local best, bestDist

	for _, inst in workspace:GetChildren() do
		if inst:IsA("BasePart") and inst.Name == "Ball" and inst.CanCollide then
			local dist = (inst.Position - hrp.Position).Magnitude
			if dist < 120 and (not bestDist or dist < bestDist) then
				best = inst
				bestDist = dist
			end
		end
	end

	return best
end

function boostBowlingBallTowardPins()
	if not CONFIG.BowlingBoostBall then return end

	local lane = getBowlingLocalLane()
	local ball = findThrownBowlingBall()
	if not ball or not lane then return end

	local pins = lane:FindFirstChild("Pins")
	local target

	if pins then
		target = pins:GetPivot().Position
	else
		for _, desc in lane:GetDescendants() do
			if desc.Name == "Pin" and desc:IsA("BasePart") then
				target = desc.Position
				break
			end
		end
	end

	if not target then return end

	local dir = (target - ball.Position) * Vector3.new(1, 0, 1)
	if dir.Magnitude < 0.1 then
		dir = ball.CFrame.LookVector
	else
		dir = dir.Unit
	end

	ball.AssemblyLinearVelocity = dir * CONFIG.BowlingBallSpeed
	ball.AssemblyAngularVelocity = Vector3.new(0, 12, 0)
end

function scheduleBowlingPinKnock()
	if not CONFIG.BowlingKnockPinsBeforeCount then return end

	for _, delay in { 2.5, CONFIG.BowlingKnockPinsDelay, 2.95 } do
		task.delay(delay, function()
			if state.bowlingInMinigame then
				knockBowlingPins()
			end
		end)
	end
end

function patchBowlingMemberFinishedRound(args)
	if args[1] ~= "MemberFinishedRound" or type(args[2]) ~= "table" then
		return args
	end

	local patched = table.clone(args[2])
	patched.Score = CONFIG.BowlingPinsPerRound
	args[2] = patched
	return args
end

function shouldFakeBowlingPinRaycast(direction)
	if not state.bowlingInMinigame or typeof(direction) ~= "Vector3" then
		return false
	end

	local mag = direction.Magnitude
	return mag > 2.5 and mag < 3.5
end

function hookBowlingGameCalls()
	if state.bowlingNetworkHooked or not CONFIG.BowlingStrikeEnabled then return end
	if not hookmetamethod or not getnamecallmethod then
		bowlingLog("No hookmetamethod - using physical pin knock")
		return
	end

	local old
	old = hookmetamethod(game, "__namecall", function(self, ...)
		local method = getnamecallmethod()

		if method == "FireServer" and CONFIG.BowlingForceScoreOnNetwork then
			local args = { ... }
			if args[1] == "MemberFinishedRound" then
				args = patchBowlingMemberFinishedRound(args)
				return old(self, table.unpack(args))
			end
		end

		if method == "Raycast" and state.bowlingInMinigame then
			local args = { ... }
			if shouldFakeBowlingPinRaycast(args[2]) then
				return nil
			end
		end

		return old(self, ...)
	end)

	state.bowlingNetworkHooked = true
	bowlingLog("Hook active via __namecall (score + raycast)")
end

function onBowlingThrow()
	if state.bowlingThrowing or not state.bowlingInMinigame or not CONFIG.BowlingStrikeEnabled then return end
	state.bowlingThrowing = true

	task.defer(boostBowlingBallTowardPins)
	scheduleBowlingPinKnock()

	task.delay(4, function()
		state.bowlingThrowing = false
	end)
end

function getBowlingBallTool()
	local char = LP.Character
	if not char then return nil end

	local tool = char:FindFirstChild("BowlingBall")
	if tool and tool:IsA("Tool") then
		return tool
	end

	local backpack = LP:FindFirstChild("Backpack")
	if backpack then
		tool = backpack:FindFirstChild("BowlingBall")
		if tool and tool:IsA("Tool") then
			return tool
		end
	end
end

function doBowlingThrow()
	if state.bowlingThrowing or not state.bowlingInMinigame then
		return
	end

	local char = LP.Character
	if not char or not char.PrimaryPart then
		state.bowlingStatus = "sem personagem"
		return
	end

	local tool = getBowlingBallTool()
	if not tool then
		state.bowlingStatus = "no ball"
		return
	end

	if CONFIG.BowlingAutoEquipBall and tool.Parent ~= char then
		tool.Parent = char
		task.wait(0.15)
	end

	if tool.Parent == char then
		pcall(function()
			tool:Activate()
		end)
		onBowlingThrow()
		state.bowlingStatus = "arremessando"
	end
end

function bindBowlingThrowInput()
	UIS.InputBegan:Connect(function(input, processed)
		if processed or not state.bowlingInMinigame or not CONFIG.BowlingStrikeEnabled then return end
		if input.UserInputType == Enum.UserInputType.MouseButton1
			or input.UserInputType == Enum.UserInputType.Touch then
			local tool = LP.Character and LP.Character:FindFirstChild("BowlingBall")
			if tool then
				onBowlingThrow()
			end
		end
	end)

	function bindTool(tool)
		if tool:IsA("Tool") and tool.Name == "BowlingBall" then
			tool.Activated:Connect(function()
				if state.bowlingInMinigame and CONFIG.BowlingStrikeEnabled then
					onBowlingThrow()
				end
			end)
		end
	end

	LP.CharacterAdded:Connect(function(char)
		char.ChildAdded:Connect(bindTool)
	end)

	if LP.Character then
		for _, child in LP.Character:GetChildren() do
			bindTool(child)
		end
	end
end

function watchBowlingMinigameState()
	RunService.Heartbeat:Connect(function()
		local now = bowlingIsInMinigame()
		if now ~= state.bowlingInMinigame then
			state.bowlingInMinigame = now
			if now then
				bowlingLog("Minigame detected - strike mode active")
				clearBowlingObstacles()
				state.bowlingStatus = CONFIG.AutoBowlingEnabled and "auto active" or "minigame"
			else
				bowlingLog("Minigame encerrado")
				state.bowlingThrowing = false
				state.bowlingStatus = CONFIG.AutoBowlingEnabled and "waiting for minigame" or "off"
			end
		end

		if state.bowlingInMinigame and CONFIG.BowlingRemoveObstacles then
			clearBowlingObstacles()
		end
	end)
end

function startBowlingObstacleScan()
	task.spawn(function()
		while true do
			if state.bowlingInMinigame and CONFIG.BowlingRemoveObstacles then
				clearBowlingObstacles()
			end
			task.wait(CONFIG.BowlingObstacleScanInterval)
		end
	end)
end

function initBowlingModule()
	if state.bowlingInitialized then return end
	state.bowlingInitialized = true

	state.bowlingClientTagData = LP and LP:FindFirstChild("ClientTagData")
	if not state.bowlingClientTagData and LP then
		task.spawn(function()
			state.bowlingClientTagData = LP:WaitForChild("ClientTagData", 120)
		end)
	end

	hookBowlingGameCalls()
	bindBowlingThrowInput()
	watchBowlingMinigameState()
	startBowlingObstacleScan()

	bowlingLog("BowlingStrike module integrated")
end

function startAutoBowling()
	CONFIG.AutoBowlingEnabled = true
	state.bowlingLastAutoThrow = 0
	state.bowlingStatus = state.bowlingInMinigame and "auto active" or "waiting for minigame"
	bowlingLog("Auto Bowling enabled")
end

function stopAutoBowling()
	CONFIG.AutoBowlingEnabled = false
	state.bowlingStatus = state.bowlingInMinigame and "minigame" or "off"
	bowlingLog("Auto Bowling disabled")
end

-- ============================================================
-- AUTO GOLF HARD (Gold Golf)
-- ============================================================

local autoGolfController = nil

function startAutoGolfHard()
	CONFIG.AutoGolfEnabled = true
	if autoGolfController and autoGolfController.Start then
		autoGolfController.Start()
		return
	end

	local hubConfig = CONFIG
	local ok, err = pcall(function()
		--[[
		    Auto Golf Hard — Piggy Intercity (Executor)
		    Does not use require(), so it stays executor-compatible.
		    Simulates player clicks instead of firing remotes directly.
		    Aims on RenderStepped at the last priority so the game does not overwrite the pendulum.
		    
		    Applied fixes:
		    - seenTargets is marked only when the target is actually selected.
		    - committedTargets is marked only when the swing is actually fired.
		    - Hard Mode detection uses any remaining target and is cached for the match.
		    - Moving targets wait for stable motion calibration before the first click.
		    - If a fired target still exists, it is released for retry.
		]]
		
		local CONFIG = {
		    HardModeOnly = true,
		    Rounds = 5,
		    TargetOrder = {
		        "Target_Blue",
		        "Target_Yellow",
		        "Target_Green",
		        "Target_Red",
		        "Target_Purple",
		    },
		    PowerReadyDelay = 0.11,
		    PowerTolerance = 1.5,
		    AimClickInterval = 0.02,
		    PowerClickInterval = 0.04,
		    HookRaycast = true,
		    BindName = "AutoGolfHard",
		    SimDt = 0.02,
		    SimMaxTime = 14,
		    MaxBounces = 2,
		    StopVelocity = 6,
		    MovingTweenHalfPeriod = 9,
		    MovingAimLead = 0.42,
		    MovingPredictionLeadMax = 2.35,
		    MovingPairReadyMinSep = 10,
		    MovingMinObservedRange = 4,
		    MovingCalibrationMaxWait = 1.6,
		    MovingEndpointStableTime = 0.28,
		    MovingEndpointMargin = 0.65,
		    MovingVelocitySmoothing = 0.28,
		    MovingMaxSpeed = 70,
		    CenterRingHitboxEnabled = true,
		    CenterRingHitboxScale = 2.35,
		    CenterRingMinHitboxSize = 16,
		    PredictIterations = 6,
		    PowerSearchStep = 2,
		    CommitRetryDelay = 1.1,
		    MovingNames = {
		        Target_Blue = true,
		        Target_Yellow = true,
		    },
		}
		
		local CollectionService = game:GetService("CollectionService")
		local Players = game:GetService("Players")
		local RunService = game:GetService("RunService")
		local VIM = game:GetService("VirtualInputManager")
		local LP = Players.LocalPlayer
		
		local HORIZ_SCALE = 0.766044443118978
		local VERT_COMP = 0.64278764
		local MAX_LAUNCH_SPEED = 200
		
		local state = {
		    hookedRaycast = false,
		    active = false,
		    phase = "idle",
		    swingStep = 0,
		    currentRound = 0,
		    roundToken = 0,
		    plannedTarget = nil,
		    plannedPower = 100,
		    plannedFlightTime = 0,
		    roundStartedAt = 0,
		    hitTargets = {},
		    seenTargets = {},
		    committedTargets = {},
		    motion = {},
		    centerRingOriginal = {},
		    powerPhaseAt = 0,
		    lastAimClickAt = 0,
		    lastPowerClickAt = 0,
		    hadPendulum = false,
		    wasInGolfMinigame = false,
		    hardModeConfirmed = false,
		    movingPairReady = false,
		    movingMaxSep = 0,
		    movingMaxSepAt = 0,
		    movingAxis = nil,
		    movingRangeMin = 0,
		    movingRangeMax = 0,
		}
		
		function log(msg)
		    print("[AutoGolfHard] " .. msg)
		end
		
		function safeNewCclosure(fn)
		    if newcclosure then
		        return newcclosure(fn)
		    end
		    return fn
		end
		
		function hasTag(inst, tag)
		    if not inst then return false end
		    if typeof(inst.HasTag) == "function" then
		        return inst:HasTag(tag)
		    end
		    return CollectionService:HasTag(inst, tag)
		end
		
		function sendClick()
		    if mouse1click then
		        local ok = pcall(mouse1click)
		        if ok then return true end
		    end
		    local ok = pcall(function()
		        local cam = workspace.CurrentCamera
		        local size = cam and cam.ViewportSize or Vector2.new(960, 540)
		        local x, y = size.X * 0.5, size.Y * 0.5
		        VIM:SendMouseButtonEvent(x, y, 0, true, game, 0)
		        VIM:SendMouseButtonEvent(x, y, 0, false, game, 0)
		    end)
		    return ok
		end
		
		function clickAim()
		    if tick() - state.lastAimClickAt < CONFIG.AimClickInterval then return false end
		    state.lastAimClickAt = tick()
		    return sendClick()
		end
		
		function clickPower()
		    if tick() - state.lastPowerClickAt < CONFIG.PowerClickInterval then return false end
		    state.lastPowerClickAt = tick()
		    return sendClick()
		end
		
		function getPlayerLane()
		    local locations = workspace:FindFirstChild("Locations")
		    local gg = locations and locations:FindFirstChild("Gold Golf")
		    local lanes = gg and gg:FindFirstChild("Minigame") and gg.Minigame:FindFirstChild("Lanes")
		    if not lanes then return nil end
		    for _, lane in lanes:GetChildren() do
		        if lane:FindFirstChild("GolfBall")
		            and lane:FindFirstChild("Targets")
		            and lane:FindFirstChild("GolfPlatform") then
		            return lane
		        end
		    end
		    return nil
		end
		
		function isInGolfMinigame()
		    local tagData = LP:FindFirstChild("ClientTagData")
		    return tagData ~= nil and hasTag(tagData, "InMinigame") and getPlayerLane() ~= nil
		end
		
		function getRoundLabel()
		    local gui = LP:FindFirstChild("PlayerGui")
		    local ui = gui and gui:FindFirstChild("MinigameUI")
		    local round = ui and ui:FindFirstChild("Round")
		    if not round then return nil end
		    local best = 0
		    for _, child in round:GetChildren() do
		        if child:IsA("TextLabel") and child.Name ~= "Label" then
		            local n = tonumber(child.Name) or tonumber(child.Text:match("Round (%d+)"))
		            if n and n > best then best = n end
		        end
		    end
		    return if best > 0 then best else nil
		end
		
		function readPowerPercent()
		    local gui = LP:FindFirstChild("PlayerGui")
		    local ui = gui and gui:FindFirstChild("MinigameUI")
		    local power = ui and ui:FindFirstChild("Power")
		    local frame = power and power:FindFirstChild("Frame")
		    local bar = frame and frame:FindFirstChild("Bar")
		    if not bar then return nil end
		    return math.clamp((1 - bar.Position.Y.Scale) * 100, 0, 100)
		end
		
		function isPowerPhaseActive()
		    local gui = LP:FindFirstChild("PlayerGui")
		    local ui = gui and gui:FindFirstChild("MinigameUI")
		    local power = ui and ui:FindFirstChild("Power")
		    local frame = power and power:FindFirstChild("Frame")
		    if not frame then return false end
		    return frame.Position.X.Scale < 1.5
		end
		
		function isHardModeLane(lane)
		    if state.hardModeConfirmed then return true end
		    for _, name in CONFIG.TargetOrder do
		        local target = lane.Targets:FindFirstChild(name)
		        local outer = target and target:FindFirstChild("OuterRing")
		        if outer then
		            return outer.Size.X <= 52
		        end
		    end
		    return false
		end
		
		function isRingFilter(params)
		    if not params or params.FilterType ~= Enum.RaycastFilterType.Include then return false, nil end
		    local filter = params.FilterDescendantsInstances
		    if not filter then return false, nil end
		    for _, inst in filter do
		        if inst and inst.Name == "CenterRing" then return true, inst end
		    end
		    for _, inst in filter do
		        if inst and (inst.Name == "OuterRing" or inst.Name == "MiddleRing") then
		            local center = inst.Parent and inst.Parent:FindFirstChild("CenterRing")
		            if center then return true, center end
		        end
		    end
		    return false, nil
		end
		
		function fakeRaycastResult(part)
		    return {
		        Instance = part,
		        Position = part.Position + Vector3.new(0, 0.05, 0),
		        Normal = Vector3.new(0, 1, 0),
		        Material = part.Material,
		        Distance = 0.05,
		    }
		end
		
		function installRaycastHook()
		    if state.hookedRaycast or not CONFIG.HookRaycast or not hookfunction then return end
		    local oldRay = workspace.Raycast
		    local ok = pcall(function()
		        workspace.Raycast = hookfunction(oldRay, safeNewCclosure(function(origin, direction, params, ...)
		            if isInGolfMinigame() then
		                local isRing, ring = isRingFilter(params)
		                if isRing and ring then return fakeRaycastResult(ring) end
		            end
		            return oldRay(origin, direction, params, ...)
		        end))
		    end)
		    if ok then
		        state.hookedRaycast = true
		        log("Raycast hook (CenterRing)")
		    end
		end
		
		function getTargetCenter(target)
		    local center = target:FindFirstChild("CenterRing")
		    return center and center.Position or target:GetPivot().Position
		end
		
		function isMovingTarget(target)
		    return target and CONFIG.MovingNames[target.Name] == true
		end

		function applyCenterRingHitboxes(lane)
		    if not CONFIG.CenterRingHitboxEnabled or not lane or not lane:FindFirstChild("Targets") then return end

		    for _, name in CONFIG.TargetOrder do
		        local target = lane.Targets:FindFirstChild(name)
		        local center = target and target:FindFirstChild("CenterRing")
		        if center and center:IsA("BasePart") then
		            if not state.centerRingOriginal[center] then
		                state.centerRingOriginal[center] = {
		                    Size = center.Size,
		                    CanQuery = center.CanQuery,
		                    CanTouch = center.CanTouch,
		                }
		            end

		            local original = state.centerRingOriginal[center].Size
		            local minSize = CONFIG.CenterRingMinHitboxSize
		            local targetSize = Vector3.new(
		                math.max(original.X * CONFIG.CenterRingHitboxScale, minSize),
		                math.max(original.Y, 1),
		                math.max(original.Z * CONFIG.CenterRingHitboxScale, minSize)
		            )

		            if (center.Size - targetSize).Magnitude > 0.05 then
		                center.Size = targetSize
		            end
		            center.CanQuery = true
		            center.CanTouch = true
		        end
		    end
		end

		function restoreCenterRingHitboxes()
		    for center, original in state.centerRingOriginal do
		        if center and center.Parent then
		            pcall(function()
		                center.Size = original.Size
		                center.CanQuery = original.CanQuery
		                center.CanTouch = original.CanTouch
		            end)
		        end
		    end
		    table.clear(state.centerRingOriginal)
		end
		
		-- ========== MOTION TRACKING ==========
		function ensureMotionSample(target)
		    if not state.motion[target] then
		        local center = getTargetCenter(target)
		        state.motion[target] = {
		            pos = center,
		            time = tick(),
		            velocity = Vector3.zero,
		            rawVelocity = Vector3.zero,
		            xRef = center.X,
		            yRef = center.Y,
		            xMin = center.X, xMax = center.X,
		            zMin = center.Z, zMax = center.Z,
		            movingAxis = nil,
		            rangeMin = 0, rangeMax = 0,
		            samples = 1,
		            ready = false,
		        }
		    end
		    return state.motion[target]
		end
		
		function trackMotion(target)
		    local now = tick()
		    local pos = getTargetCenter(target)
		    local sample = ensureMotionSample(target)
		    local dt = now - sample.time
		    if dt > 0.015 then
		        local rawVelocity = (pos - sample.pos) / dt
		        if rawVelocity.Magnitude <= CONFIG.MovingMaxSpeed then
		            local alpha = CONFIG.MovingVelocitySmoothing
		            sample.rawVelocity = rawVelocity
		            sample.velocity = sample.velocity:Lerp(rawVelocity, alpha)
		        end
		        sample.pos = pos
		        sample.time = now
		        sample.samples += 1
		    end
		    sample.xRef = pos.X
		    sample.yRef = pos.Y
		    sample.xMin = math.min(sample.xMin, pos.X)
		    sample.xMax = math.max(sample.xMax, pos.X)
		    sample.zMin = math.min(sample.zMin, pos.Z)
		    sample.zMax = math.max(sample.zMax, pos.Z)
		
		    -- Do not mark seenTargets here. It is marked only when a round selects the target.
		
		    if isMovingTarget(target) then
		        local dx = sample.xMax - sample.xMin
		        local dz = sample.zMax - sample.zMin
		        if dx > 1.5 or dz > 1.5 then
		            if not sample.movingAxis or (dx > dz and dx > 1.5) then
		                sample.movingAxis = "X"
		            elseif dz > dx and dz > 1.5 then
		                sample.movingAxis = "Z"
		            end
		        end
		    end
		end
		
		function calibrateMovingPair(lane)
		    local targets = lane.Targets
		    local yellow = targets:FindFirstChild("Target_Yellow")
		    local blue = targets:FindFirstChild("Target_Blue")
		    if not yellow or not blue then return end
		
		    local ySample = ensureMotionSample(yellow)
		    local bSample = ensureMotionSample(blue)
		
		    local dx = math.max(ySample.xMax - ySample.xMin, bSample.xMax - bSample.xMin)
		    local dz = math.max(ySample.zMax - ySample.zMin, bSample.zMax - bSample.zMin)
		    local axis = (dx > dz) and "X" or "Z"
		    for _, target in { yellow, blue } do
		        local sample = ensureMotionSample(target)
		        local pivot = target:GetPivot().Position
		        sample.movingAxis = axis
		        sample.xRef = pivot.X
		        sample.yRef = pivot.Y
		    end
		end
		
		function updatePairEndpoints(lane)
		    local targets = lane.Targets
		    local yellow = targets:FindFirstChild("Target_Yellow")
		    local blue = targets:FindFirstChild("Target_Blue")
		    if not yellow or not blue then return end
		
		    local yc = getTargetCenter(yellow)
		    local bc = getTargetCenter(blue)
		    local dx = math.abs(yc.X - bc.X)
		    local dz = math.abs(yc.Z - bc.Z)
		    local sep, axis, lo, hi
		    if dx > dz then
		        axis, sep, lo, hi = "X", dx, math.min(yc.X, bc.X), math.max(yc.X, bc.X)
		    else
		        axis, sep, lo, hi = "Z", dz, math.min(yc.Z, bc.Z), math.max(yc.Z, bc.Z)
		    end
		
		    local now = tick()
		    if sep > state.movingMaxSep + 0.05 then
		        state.movingMaxSep = sep
		        state.movingMaxSepAt = now
		        state.movingAxis = axis
		        state.movingRangeMin = lo - CONFIG.MovingEndpointMargin
		        state.movingRangeMax = hi + CONFIG.MovingEndpointMargin
		    end
		
		    if state.movingMaxSep < CONFIG.MovingPairReadyMinSep then return end
		    if now - state.movingMaxSepAt < CONFIG.MovingEndpointStableTime then return end
		
		    for _, target in { yellow, blue } do
		        local sample = ensureMotionSample(target)
		        sample.movingAxis = state.movingAxis or axis
		        sample.rangeMin = state.movingRangeMin
		        sample.rangeMax = state.movingRangeMax
		        sample.ready = true
		    end
		    state.movingPairReady = true
		end
		
		function advancePingPong1D(pos, vel, length, dt)
		    if length < 0.01 then return pos end
		    local remaining = dt
		    local x = math.clamp(pos, 0, length)
		    local v = vel
		    if math.abs(v) < 0.05 then
		        v = length / CONFIG.MovingTweenHalfPeriod
		        if x > length * 0.5 then v = -math.abs(v) else v = math.abs(v) end
		    end
		    while remaining > 1e-5 do
		        if v > 0 then
		            local dist = length - x
		            if dist <= 1e-4 then
		                x = length
		                v = -math.abs(v)
		                continue
		            end
		            local timeToEnd = dist / v
		            if remaining <= timeToEnd then
		                x += v * remaining
		                remaining = 0
		            else
		                remaining -= timeToEnd
		                x = length
		                v = -v
		            end
		        else
		            local speed = math.abs(v)
		            if x <= 1e-4 then
		                x = 0
		                v = speed
		                continue
		            end
		            local timeToEnd = x / speed
		            if remaining <= timeToEnd then
		                x += v * remaining
		                remaining = 0
		            else
		                remaining -= timeToEnd
		                x = 0
		                v = speed
		            end
		        end
		    end
		    return math.clamp(x, 0, length)
		end
		
		function predictMovingCenter(sample, lead)
		    lead = math.clamp(lead or 0, 0, CONFIG.MovingPredictionLeadMax)
		    if not sample.ready then
		        return sample.pos + sample.velocity * lead
		    end
		    local axis = sample.movingAxis
		    if not axis then
		        return sample.pos + sample.velocity * lead
		    end
		    local length = sample.rangeMax - sample.rangeMin
		    if length < 1.5 then
		        return sample.pos + sample.velocity * lead
		    end
		    local posNow, velNow
		    if axis == "X" then
		        posNow = sample.pos.X - sample.rangeMin
		        velNow = sample.velocity.X
		    else
		        posNow = sample.pos.Z - sample.rangeMin
		        velNow = sample.velocity.Z
		    end
		    local futureVal = sample.rangeMin + advancePingPong1D(posNow, velNow, length, lead)
		    if axis == "X" then
		        return Vector3.new(futureVal, sample.yRef, sample.pos.Z)
		    else
		        return Vector3.new(sample.xRef, sample.yRef, futureVal)
		    end
		end
		
		function getAimLead(target, flightTime)
		    if not isMovingTarget(target) then return 0 end
		    return math.clamp(CONFIG.MovingAimLead + (flightTime or 0), 0, CONFIG.MovingPredictionLeadMax)
		end
		
		function isMovingPredictionReady(target)
		    if not isMovingTarget(target) then return true end
		
		    local sample = state.motion[target]
		    if not sample or sample.samples < 3 then return false end
		
		    local observedRange = math.max(sample.xMax - sample.xMin, sample.zMax - sample.zMin)
		    local readyRange = sample.rangeMax - sample.rangeMin
		    if sample.ready and readyRange >= CONFIG.MovingPairReadyMinSep then
		        return true
		    end
		    if observedRange >= CONFIG.MovingMinObservedRange then
		        return true
		    end
		
		    return state.roundStartedAt > 0
		        and tick() - state.roundStartedAt >= CONFIG.MovingCalibrationMaxWait
		end
		
		function predictTargetPosition(target, lead)
		    trackMotion(target)
		    if not isMovingTarget(target) then
		        return getTargetCenter(target)
		    end
		    local sample = state.motion[target]
		    if not sample then return getTargetCenter(target) end
		    return predictMovingCenter(sample, lead)
		end
		
		-- ========== PHYSICS AND AIM ==========
		function horizontalUnit(from, to)
		    local flat = Vector3.new(to.X - from.X, 0, to.Z - from.Z)
		    if flat.Magnitude < 0.05 then return Vector3.new(0, 0, -1) end
		    return flat.Unit
		end
		
		function aimPendulum(lane, goal)
		    local ball = lane.GolfBall
		    local pendulum = lane:FindFirstChild("Pendulum")
		    if not (ball and pendulum) then return end
		    local from = ball.Position
		    local lookAt = CFrame.lookAt(from, Vector3.new(goal.X, from.Y, goal.Z))
		    pendulum.CFrame = lookAt * CFrame.new(0, 0, -pendulum.Size.Z * 0.5)
		end
		
		function makeRaycastParams(platform)
		    local params = RaycastParams.new()
		    params.FilterType = Enum.RaycastFilterType.Include
		    params.FilterDescendantsInstances = { platform }
		    return params
		end
		
		function simulatePutt(startPos, direction, power, platform)
		    local speed = math.clamp(power, 0, 100) / 100 * MAX_LAUNCH_SPEED
		    local unit = Vector3.new(direction.X, 0, direction.Z)
		    unit = if unit.Magnitude < 1e-4 then Vector3.new(0, 0, -1) else unit.Unit
		    local velocity = (unit * HORIZ_SCALE + Vector3.new(0, VERT_COMP, 0)) * speed
		    local position = startPos
		    local gravity = Vector3.new(0, -workspace.Gravity, 0)
		    local params = makeRaycastParams(platform)
		    local bounceCount = 0
		    local elapsed = 0
		    while elapsed < CONFIG.SimMaxTime do
		        local dt = CONFIG.SimDt
		        velocity = velocity + gravity * dt
		        local nextPos = position + velocity * dt + gravity * 0.5 * dt * dt
		        local delta = nextPos - position
		        if delta.Magnitude <= 0 then break end
		        local hit = workspace:Raycast(position, delta, params)
		        if hit then
		            position = hit.Position + hit.Normal * 0.01
		            if bounceCount >= CONFIG.MaxBounces then return position, elapsed end
		            local restitution = ({0.4, 0.5})[math.clamp(bounceCount + 1, 1, 2)]
		            local friction = ({0.2, 0.3})[math.clamp(bounceCount + 1, 1, 2)]
		            local vn = velocity:Dot(hit.Normal)
		            local tangential = velocity - (1 + restitution) * vn * hit.Normal
		            local normalPart = hit.Normal * tangential:Dot(hit.Normal)
		            velocity = normalPart + (tangential - normalPart) * friction
		            bounceCount += 1
		            if velocity.Magnitude < CONFIG.StopVelocity then return position, elapsed end
		        else
		            position = nextPos
		        end
		        elapsed += dt
		    end
		    return position, elapsed
		end
		
		function landingError2D(landing, goal)
		    local a = Vector3.new(landing.X, 0, landing.Z)
		    local b = Vector3.new(goal.X, 0, goal.Z)
		    return (a - b).Magnitude
		end
		
		function solvePower(ballPos, direction, target, platform)
		    local moving = isMovingTarget(target)
		    local iterations = if moving then CONFIG.PredictIterations + 2 else CONFIG.PredictIterations
		    local bestPower, bestTime, bestErr = 100, 0, math.huge
		
		    for power = 10, 100, CONFIG.PowerSearchStep do
		        local landing, time = simulatePutt(ballPos, direction, power, platform)
		        local goal = predictTargetPosition(target, time)
		        local err = landingError2D(landing, goal)
		        if err < bestErr then
		            bestErr, bestPower, bestTime = err, power, time
		        end
		    end
		
		    for _ = 1, iterations do
		        local aimLead = getAimLead(target, bestTime)
		        local aimGoal = predictTargetPosition(target, aimLead)
		        direction = horizontalUnit(ballPos, aimGoal)
		        bestErr = math.huge
		        local pMin = math.max(10, bestPower - (if moving then 10 else 6))
		        local pMax = math.min(100, bestPower + (if moving then 10 else 6))
		        for power = pMin, pMax, 1 do
		            local landing, time = simulatePutt(ballPos, direction, power, platform)
		            local goal = predictTargetPosition(target, time)
		            local err = landingError2D(landing, goal)
		            if err < bestErr then
		                bestErr, bestPower, bestTime = err, power, time
		            end
		        end
		    end
		    return bestPower, bestTime, bestErr
		end
		
		-- ========== GERENCIAMENTO DE ALVOS ==========
		function markTargetHit(name)
		    if name then
		        state.hitTargets[name] = true
		        state.committedTargets[name] = nil
		    end
		end
		
		function markTargetCommitted(name)
		    if name then
		        state.committedTargets[name] = tick()
		        state.seenTargets[name] = true
		    end
		end
		
		function clearMotionForName(name)
		    for target in state.motion do
		        if target.Name == name then state.motion[target] = nil end
		    end
		end
		
		function syncDestroyedTargets(lane)
		    for _, name in CONFIG.TargetOrder do
		        if not state.hitTargets[name] 
		           and not lane.Targets:FindFirstChild(name) 
		           and (state.seenTargets[name] or state.committedTargets[name]) then
		            markTargetHit(name)
		            clearMotionForName(name)
		        end
		    end
		    if state.plannedTarget and not state.plannedTarget.Parent then
		        markTargetHit(state.plannedTarget.Name)
		        state.motion[state.plannedTarget] = nil
		        state.plannedTarget = nil
		    end
		end
		
		function hasPendingCommittedTarget(lane)
		    for _, name in CONFIG.TargetOrder do
		        local committedAt = state.committedTargets[name]
		        if committedAt and not state.hitTargets[name] then
		            if not lane.Targets:FindFirstChild(name) then
		                markTargetHit(name)
		                clearMotionForName(name)
		            elseif tick() - committedAt >= CONFIG.CommitRetryDelay then
		                state.committedTargets[name] = nil
		                log(("Retry released -> %s still exists"):format(name))
		            else
		                return true
		            end
		        end
		    end
		    return false
		end
		
		function pickTarget(lane)
		    for _, name in CONFIG.TargetOrder do
		        if state.hitTargets[name] or state.committedTargets[name] then continue end
		        local target = lane.Targets:FindFirstChild(name)
		        if target and target:FindFirstChild("CenterRing") then
		            return target, name
		        end
		    end
		    return nil, nil
		end
		
		function beginRound(target, targetName)
		    state.phase = "aim"
		    state.swingStep = 0
		    state.plannedTarget = target
		    state.plannedPower = nil
		    state.plannedFlightTime = 0
		    state.roundStartedAt = tick()
		    state.powerPhaseAt = 0
		    state.lastAimClickAt = 0
		
		    state.seenTargets[targetName] = true   -- Only mark here.
		
		    log(("Round %d -> %s"):format(state.currentRound > 0 and state.currentRound or 1, targetName))
		end
		
		function resetSwingState()
		    state.phase = "idle"
		    state.swingStep = 0
		    state.plannedTarget = nil
		    state.plannedPower = nil
		    state.plannedFlightTime = 0
		    state.roundStartedAt = 0
		    state.powerPhaseAt = 0
		    state.lastAimClickAt = 0
		end
		
		function resetMatch()
		    restoreCenterRingHitboxes()
		    resetSwingState()
		    state.currentRound = 0
		    state.hadPendulum = false
		    state.hardModeConfirmed = false
		    state.movingPairReady = false
		    state.movingMaxSep = 0
		    state.movingMaxSepAt = 0
		    state.movingAxis = nil
		    state.movingRangeMin = 0
		    state.movingRangeMax = 0
		    table.clear(state.hitTargets)
		    table.clear(state.seenTargets)
		    table.clear(state.committedTargets)
		    table.clear(state.motion)
		    table.clear(state.centerRingOriginal)
		    state.roundToken += 1
		end
		
		-- ========== LOOP PRINCIPAL ==========
		function onRenderStep()
		    if not isInGolfMinigame() then
		        if state.wasInGolfMinigame then resetMatch() end
		        state.wasInGolfMinigame = false
		        return
		    end
		    state.wasInGolfMinigame = true
		
		    local lane = getPlayerLane()
		    if not lane then return end
		
		    if CONFIG.HardModeOnly then
		        if not isHardModeLane(lane) then return end
		        state.hardModeConfirmed = true
		    end

		    applyCenterRingHitboxes(lane)
		
		    -- Always track moving targets.
		    for _, name in pairs({"Target_Yellow", "Target_Blue"}) do
		        local t = lane.Targets:FindFirstChild(name)
		        if t then trackMotion(t) end
		    end
		
		    syncDestroyedTargets(lane)
		    calibrateMovingPair(lane)
		    updatePairEndpoints(lane)
		
		    local round = getRoundLabel()
		    if round and round ~= state.currentRound then
		        state.currentRound = round
		        state.roundToken += 1
		        resetSwingState()
		        syncDestroyedTargets(lane)
		    end
		
		    local pendulum = lane:FindFirstChild("Pendulum")
		    local hasPendulum = pendulum ~= nil
		    local powerActive = isPowerPhaseActive()
		
		    -- Keep trying to select a target while the pendulum exists and no target is planned.
		    if hasPendulum and state.swingStep == 0 and not state.plannedTarget then
		        if hasPendingCommittedTarget(lane) then
		            state.hadPendulum = hasPendulum
		            return
		        end
		
		        local target, targetName = pickTarget(lane)
		        if target then
		            beginRound(target, targetName)
		        else
		            state.hadPendulum = hasPendulum
		            return
		        end
		    end
		
		    state.hadPendulum = hasPendulum
		
		    if not hasPendulum and not powerActive then
		        if state.swingStep >= 2 then
		            syncDestroyedTargets(lane)
		            resetSwingState()
		        end
		        return
		    end
		
		    local target = state.plannedTarget
		    if not target or not target.Parent then
		        state.plannedTarget = nil
		        return
		    end
		
		    local aimLead = if isMovingTarget(target)
		        then getAimLead(target, state.plannedFlightTime)
		        else 0
		
		    local goal = predictTargetPosition(target, aimLead)
		
		    if pendulum and state.swingStep < 3 then
		        aimPendulum(lane, goal)
		    end
		
		    -- Swing state machine.
		    if state.swingStep == 0 then
		        if not isMovingPredictionReady(target) then return end
		        clickAim()
		        if powerActive then
		            state.swingStep = 1
		            state.powerPhaseAt = tick()
		            log("Click 1/2 OK - power bar opened")
		        end
		        return
		    end
		
		    if state.swingStep == 1 then
		        if not powerActive then
		            clickAim()
		            return
		        end
		        if state.powerPhaseAt == 0 then state.powerPhaseAt = tick() end
		        if tick() - state.powerPhaseAt < CONFIG.PowerReadyDelay then return end
		        if not isMovingPredictionReady(target) then return end
		
		        local ball = lane.GolfBall
		        local aimGoal = predictTargetPosition(target, CONFIG.MovingAimLead)
		        local dir = horizontalUnit(ball.Position, aimGoal)
		        local power, flightTime, err = solvePower(ball.Position, dir, target, lane.GolfPlatform)
		        state.plannedPower = power
		        state.plannedFlightTime = flightTime
		        state.swingStep = 2
		        log(("Target power: %.1f | predict %.2fs | err %.2f"):format(power, flightTime, err))
		        return
		    end
		
		    if state.swingStep == 2 then
		        if not powerActive then
		            state.swingStep = 1
		            return
		        end
		        local powerNow = readPowerPercent()
		        local targetPower = state.plannedPower or 100
		        if not powerNow then return end
		        if math.abs(powerNow - targetPower) <= CONFIG.PowerTolerance or powerNow >= targetPower then
		            if clickPower() then
		                markTargetCommitted(target.Name)
		                state.swingStep = 3
		                state.phase = "flight"
		                log(("Click 2/2 (swing @ %.1f) -> %s"):format(powerNow, target.Name))
		            end
		        end
		        return
		    end
		end
		
		function startLoop()
		    if state.active then return end
		    state.active = true
		    RunService:BindToRenderStep(CONFIG.BindName, Enum.RenderPriority.Last.Value, function()
		        pcall(onRenderStep)
		    end)
		end
		
		function stopLoop()
		    if not state.active then return end
		    state.active = false
		    pcall(function()
		        RunService:UnbindFromRenderStep(CONFIG.BindName)
		    end)
		    restoreCenterRingHitboxes()
		end
		
		function waitReady()
		    repeat task.wait() until game:IsLoaded()
		    if not LP then LP = Players.LocalPlayer or Players.PlayerAdded:Wait() end
		    LP:WaitForChild("ClientTagData", 120)
		    task.wait(1)
		end
		
		task.spawn(function()
		    local ok, err = pcall(function()
		        waitReady()
		        if not hubConfig.AutoGolfEnabled then return end
		        installRaycastHook()
		        startLoop()
		        log("Active - simulated clicks + RenderStepped aim (Last)")
		        log("Hard Mode | moving-target prediction | retry enabled")
		    end)
		    if not ok then
		        warn("[AutoGolfHard] ERRO: " .. tostring(err))
		        stopLoop()
		    end
		end)
		
		autoGolfController = {
		    Config = CONFIG,
		    State = state,
		    ClickAim = clickAim,
		    ClickPower = clickPower,
		    Reset = resetMatch,
		    Stop = stopLoop,
		    Start = startLoop,
		}
		
	end)

	if ok then
		_G.AutoGolfHard = autoGolfController
		log("Auto Golf Hard enabled")
	else
		CONFIG.AutoGolfEnabled = false
		warnLog("Auto Golf Hard error: " .. tostring(err))
	end
end

function stopAutoGolfHard()
	CONFIG.AutoGolfEnabled = false
	local controller = autoGolfController or _G.AutoGolfHard
	if controller and controller.Stop then
		pcall(controller.Stop)
	end
	log("Auto Golf Hard disabled")
end

function resetAutoGolfHard()
	local controller = autoGolfController or _G.AutoGolfHard
	if controller and controller.Reset then
		pcall(controller.Reset)
	end
end

-- ============================================================
-- CHARACTER
-- ============================================================

function applyNoClip(character)
	if not CONFIG.CharacterNoClip or not character then
		return
	end
	for _, inst in character:GetDescendants() do
		if inst:IsA("BasePart") then
			inst.CanCollide = false
		end
	end
end

function clearLocalLandingEffects(character)
	if not CONFIG.CharacterNoFallLanding or not character then
		return
	end

	if character:GetAttribute("HardLanding") == true then
		character:SetAttribute("HardLanding", false)
	end

	local speedBoost = character:GetAttribute("SpeedBoost")
	if type(speedBoost) == "string" and string.find(speedBoost, "0.4", 1, true) then
		character:SetAttribute("SpeedBoost", nil)
	end

	pcall(function()
		RunService:UnbindFromRenderStep("LandingTilt")
	end)
end

function applyCharacterModifiers()
	local char = getCharacter()
	local humanoid = char and char:FindFirstChildOfClass("Humanoid")
	if not humanoid then
		return
	end

	if CONFIG.CharacterSpeedEnabled then
		humanoid.WalkSpeed = math.clamp(tonumber(CONFIG.CharacterWalkSpeed) or 16, 0, 250)
	end

	if CONFIG.CharacterJumpEnabled then
		local jumpValue = math.clamp(tonumber(CONFIG.CharacterJumpPower) or 50, 0, 250)
		humanoid.UseJumpPower = true
		humanoid.JumpPower = jumpValue
	end

	if CONFIG.CharacterAntiSit and humanoid.Sit then
		humanoid.Sit = false
	end

	if CONFIG.CharacterPlatformStandGuard and humanoid.PlatformStand then
		humanoid.PlatformStand = false
	end

	clearLocalLandingEffects(char)
	applyNoClip(char)
end

function setupCharacterHooks(character)
	if not character then
		return
	end

	ensureModelPrimaryPart(character)

	if CONFIG.CharacterNoFallLanding then
		clearLocalLandingEffects(character)
	end

	table.insert(state.connections, character.AttributeChanged:Connect(function(attributeName)
		if attributeName == "HardLanding" or attributeName == "SpeedBoost" then
			clearLocalLandingEffects(character)
		end
	end))

	table.insert(state.connections, character.DescendantAdded:Connect(function(inst)
		if inst:IsA("BasePart") then
			if not character.PrimaryPart then
				task.defer(function()
					ensureModelPrimaryPart(character)
				end)
			end
			if CONFIG.CharacterNoClip then
				inst.CanCollide = false
			end
		end
	end))

	task.defer(applyCharacterModifiers)
end

function parseHexColor(text)
	if type(text) ~= "string" then
		return nil
	end
	local hex = text:gsub("#", ""):gsub("%s+", "")
	if hex == "" then
		return nil
	end
	if #hex == 3 then
		hex = hex:sub(1, 1):rep(2) .. hex:sub(2, 2):rep(2) .. hex:sub(3, 3):rep(2)
	end
	if #hex ~= 6 or not hex:match("^[%da-fA-F]+$") then
		return nil
	end
	return Color3.fromRGB(
		tonumber(hex:sub(1, 2), 16),
		tonumber(hex:sub(3, 4), 16),
		tonumber(hex:sub(5, 6), 16)
	)
end

function getCurrentAppearanceAttributes()
	local char = getCharacter()
	local appearance = char and char:FindFirstChild("Appearance")
	if appearance then
		return appearance:GetAttributes()
	end
	return {}
end

function getCurrentAppearanceState()
	local _, slot = getLoadedSessionState()
	local attrs = getCurrentAppearanceAttributes()

	return {
		Species = tostring((slot and safeRecordGet(slot, "Species")) or attrs.Species or ""),
		SpeciesType = tonumber((slot and safeRecordGet(slot, "SpeciesType")) or attrs.SpeciesType or 1) or 1,
		Gender = tostring((slot and safeRecordGet(slot, "Gender")) or attrs.Gender or ""),
		UndershirtColor = attrs.UndershirtColor,
	}, attrs
end

function applyCurrentAppearanceToConfig()
	local current, attrs = getCurrentAppearanceState()
	CONFIG.AppearanceClass = tostring(attrs.Class or CONFIG.AppearanceClass)
	CONFIG.AppearanceGender = current.Gender ~= "" and current.Gender or CONFIG.AppearanceGender
	CONFIG.AppearanceSpecies = current.Species ~= "" and current.Species or CONFIG.AppearanceSpecies
	CONFIG.AppearanceSpeciesType = current.SpeciesType or CONFIG.AppearanceSpeciesType
	CONFIG.AppearanceShirt = tostring(attrs.Shirt or "")
	CONFIG.AppearancePants = tostring(attrs.Pants or "")
	CONFIG.AppearanceArmor = tostring(attrs.Armor or "")
	CONFIG.AppearanceArmorAddons = tostring(attrs.ArmorAddons or "")
	return attrs
end

function buildAppearancePayload()
	local current = getCurrentAppearanceState()
	local payload = {
		Species = {
			CONFIG.AppearanceSpecies ~= "" and CONFIG.AppearanceSpecies or current.Species,
			math.clamp(math.floor((tonumber(CONFIG.AppearanceSpeciesType) or current.SpeciesType or 1) + 0.5), 0, 255),
		},
		Gender = CONFIG.AppearanceGender ~= "" and CONFIG.AppearanceGender or current.Gender,
		UndershirtColor = parseHexColor(CONFIG.AppearanceUndershirtColor) or current.UndershirtColor,
	}

	return payload, current
end

function getAppearancePayloadChanges(payload, current)
	local changes = {}

	if payload.Species[1] ~= current.Species then
		table.insert(changes, "Species")
	end
	if payload.Species[2] ~= current.SpeciesType then
		table.insert(changes, "SpeciesType")
	end
	if payload.Gender ~= current.Gender then
		table.insert(changes, "Gender")
	end
	if payload.UndershirtColor and not valuesEqual(payload.UndershirtColor, current.UndershirtColor) then
		table.insert(changes, "UndershirtColor")
	end

	return changes
end

function fireRemoteAppearance()
	local _, slot, saveFile, sessionError = getLoadedSessionState()
	if not slot or not saveFile then
		return false, sessionError or "appearance session is unavailable"
	end

	local remote = ReplicatedStorage:FindFirstChild("Network")
		and ReplicatedStorage.Network:FindFirstChild("CharacterCustomization")
		and ReplicatedStorage.Network.CharacterCustomization:FindFirstChild("CustomizeCharacter")
	if not remote then
		return false, "CustomizeCharacter remote was not found"
	end

	local payload, current = buildAppearancePayload()
	local changes = getAppearancePayloadChanges(payload, current)
	if #changes == 0 then
		return false, "No supported change is pending. This action only updates Species, SpeciesType, Gender, and UndershirtColor."
	end

	local ok, err = pcall(function()
		remote:FireServer(payload)
	end)
	if not ok then
		return false, err
	end

	local observed = waitForCondition(1.5, function()
		local latest = getCurrentAppearanceState()
		return latest.Species == payload.Species[1]
			and latest.SpeciesType == payload.Species[2]
			and latest.Gender == payload.Gender
			and valuesEqual(latest.UndershirtColor, payload.UndershirtColor)
	end, 0.05)

	if not observed then
		return false, "Remote fired, but no replicated appearance change was observed."
	end

	return true, "Applied: " .. table.concat(changes, ", ")
end

function openNativeAppearanceUi()
	local _, slot, saveFile, sessionError = getLoadedSessionState()
	if not slot or not saveFile then
		return false, sessionError or "appearance session is unavailable"
	end

	local module = findLoadedChangeAppearanceModule()
	if not module then
		return false, "Loaded ChangeAppearance module was not found"
	end

	local char = getCharacter()
	if not char then
		return false, "Character was not ready"
	end
	if not char:FindFirstChild("Appearance") then
		return false, "Appearance folder was not ready"
	end

	local clientTagData = getClientTagData()
	if clientTagData and hasTag(clientTagData, "InChangeAppearanceUI") then
		return true, "ChangeAppearance UI is already open"
	end

	local interacted = char
	if workspace:FindFirstChild("NPCs") then
		for _, npc in workspace.NPCs:GetDescendants() do
			if npc:IsA("Model") and npc:FindFirstChild("HumanoidRootPart") then
				interacted = npc
				break
			end
		end
	end

	local openFinished = false
	local openError = nil
	task.spawn(function()
		local ok, result = pcall(function()
			return module:Open(interacted)
		end)
		openFinished = true
		if not ok then
			openError = result
		end
	end)

	local opened = waitForCondition(1.25, function()
		local tagData = getClientTagData()
		if tagData and hasTag(tagData, "InChangeAppearanceUI") then
			return true
		end

		local playerGui = LP and LP:FindFirstChild("PlayerGui")
		local ui = playerGui and playerGui:FindFirstChild("ChangeAppearanceUI")
		local main = ui and ui:FindFirstChild("Main")
		return main and math.abs(main.AnchorPoint.X - 0.5) <= 0.01
	end, 0.05)

	if opened then
		return true, "ChangeAppearance UI opened"
	end

	if openError then
		return false, tostring(openError)
	end

	if openFinished then
		return false, "ChangeAppearance returned without opening the UI"
	end

	return false, "ChangeAppearance UI did not open"
end

function syncRuntimeFromConfig()
	if CONFIG.AutoFarmEnabled then
		startAutoFarm()
	else
		stopAutoFarm()
	end

	if CONFIG.AutoBowlingEnabled then
		startAutoBowling()
	else
		stopAutoBowling()
	end

	if CONFIG.AutoGolfEnabled then
		startAutoGolfHard()
	else
		stopAutoGolfHard()
	end

	applyCharacterModifiers()
end
