	{ Name = "SQ_TracingTags", DisplayName = "Tracing Tags", Group = "Side", StarterNpc = "Airport_PvtMaya" },
	{ Name = "SQ_DesperadoDispatch", DisplayName = "Desperado Dispatch", Group = "Side", StarterNpc = "LiberatorOutpost_Biscuit" },
	{ Name = "SQ_WheresTheWool", DisplayName = "Where's The Wool", Group = "Side", StarterNpc = "Freefall_Sharon" },
	{ Name = "SQ_RemedyRun", DisplayName = "Remedy Run", Group = "Side", StarterNpc = "MoralesHospital_Tabbu_Shop" },
	{ Name = "SQ_PendingPaint", DisplayName = "Pending Paint", Group = "Side", StarterNpc = "Freefall_Durian" },
	{ Name = "SQ_BearingArms", DisplayName = "Bearing Arms", Group = "Side", StarterNpc = "Lumbermill_Baren" },
	{ Name = "SQ_SurgicalSearch", DisplayName = "Surgical Search", Group = "Side", StarterNpc = "Shadewood_Tucker" },
}

local QUEST_START_CATALOG_BY_NAME = {}
for _, entry in QUEST_START_CATALOG do
	QUEST_START_CATALOG_BY_NAME[entry.Name] = entry
end

function splitCamelWords(text)
	text = tostring(text or "")
	text = text:gsub("([a-z])([A-Z])", "%1 %2")
	text = text:gsub("([A-Z])([A-Z][a-z])", "%1 %2")
	return text
end

function cleanupLocalJanitorItem(item)
	local itemType = typeof(item)
	if itemType == "RBXScriptConnection" then
		pcall(function()
			item:Disconnect()
		end)
		return
	end
	if type(item) == "function" then
		pcall(item)
		return
	end
	if type(item) == "table" then
		if type(item.Destroy) == "function" then
			pcall(function()
				item:Destroy()
			end)
			return
		end
		if type(item.Cleanup) == "function" then
			pcall(function()
				item:Cleanup()
			end)
			return
		end
		if type(item.Remove) == "function" then
			pcall(function()
				item:Remove()
			end)
		end
	end
end

function createLocalJanitor()
	local janitor = {
		_items = {},
	}

	function janitor:Add(item, _, key)
		local slot = key or (#self._items + 1)
		if key ~= nil then
			self:Remove(key)
		end
		self._items[slot] = item
		return item
	end

	function janitor:Remove(key)
		local item = self._items[key]
		if item == nil then
			return
		end
		self._items[key] = nil
		cleanupLocalJanitorItem(item)
	end

	function janitor:Cleanup()
		for key, item in pairs(self._items) do
			self._items[key] = nil
			cleanupLocalJanitorItem(item)
		end
	end

	function janitor:Destroy()
		self:Cleanup()
	end

	return janitor
end

function isSignalLike(value)
	return type(value) == "table"
		and (type(value.Connect) == "function" or type(value.Once) == "function")
end

function findGcTable(predicate)
	if typeof(getgc) ~= "function" then
		return nil
	end

	for _, obj in getgc(true) do
		if type(obj) == "table" then
			local ok, matches = pcall(predicate, obj)
			if ok and matches then
				return obj
			end
		end
	end

	return nil
end

function discoverQuestRuntime(force)
	if force then
		state.questRuntime = {}
	end

	local runtime = state.questRuntime
	if not runtime.questClient then
		runtime.questClient = findGcTable(function(tbl)
			return type(rawget(tbl, "GetQuestByName")) == "function"
				and type(rawget(tbl, "Quests")) == "table"
				and type(rawget(tbl, "Waypoints")) == "table"
				and isSignalLike(rawget(tbl, "QuestStarted"))
		end)
	end
	if not runtime.dialogUi then
		runtime.dialogUi = findGcTable(function(tbl)
			return type(rawget(tbl, "Open")) == "function"
				and type(rawget(tbl, "Close")) == "function"
				and type(rawget(tbl, "Update")) == "function"
				and isSignalLike(rawget(tbl, "InputRegistered"))
		end)
	end
	if not runtime.popup then
		runtime.popup = findGcTable(function(tbl)
			return type(rawget(tbl, "Open")) == "function"
				and type(rawget(tbl, "Setup")) == "function"
				and isSignalLike(rawget(tbl, "CloseSignal"))
		end)
	end
	if not runtime.sessionManager then
		runtime.sessionManager = findLoadedSessionManager()
			or findSessionManagerFromQuestRuntime(runtime.questClient)
			or findGcTable(function(tbl)
				return isSessionManagerTable(tbl)
			end)
	end
	if not runtime.profileIndex then
		runtime.profileIndex = findGcTable(function(tbl)
			return type(rawget(tbl, "GetProfiles")) == "function"
				and type(rawget(tbl, "GetProfileByName")) == "function"
				and type(rawget(tbl, "GetProfileUniqueId")) == "function"
		end)
	end
	if not runtime.dialogUtil then
		runtime.dialogUtil = findGcTable(function(tbl)
			return type(rawget(tbl, "CanInteract")) == "function"
				and type(rawget(tbl, "CanPartyMemberStartConversation")) == "function"
		end)
	end

	return runtime
end

function ensureQuestRuntime(force)
	return discoverQuestRuntime(force)
end

function getQuestWindow()
	return state.uiWindow
end

function questNotify(title, content, color)
	local window = getQuestWindow()
	if window and window.Notify then
		window:Notify({
			Title = title,
			Content = content,
			Color = color,
			Duration = 4,
		})
	end
end

function getQuestDisplayNameFromEntry(entry)
	if entry and entry.DisplayName and entry.DisplayName ~= "" then
		return entry.DisplayName
	end

	local rawName = entry and entry.Name or "Quest"
	rawName = rawName:gsub("^[A-Z][A-Z]_", "")
	rawName = rawName:gsub("_", " ")
	return splitCamelWords(rawName)
end

function getQuestDisplayName(quest)
	if not quest then
		return "Quest"
	end

	local ok, pathDef = pcall(function()
		return quest:GetPathDef()
	end)
	if ok and type(pathDef) == "table" and pathDef.DisplayName and pathDef.DisplayName ~= "" then
		return pathDef.DisplayName
	end

	local definition = rawget(quest, "Definition")
	if type(definition) == "table" and definition.DisplayName and definition.DisplayName ~= "" then
		return definition.DisplayName
	end

	return quest.Name or "Quest"
end

function getQuestObjectiveDefSafe(quest)
	if not quest or type(quest.GetObjectiveDef) ~= "function" then
		return nil
	end

	local ok, objective = pcall(function()
		return quest:GetObjectiveDef()
	end)
	if ok then
		return objective
	end

	return nil
end

function getLocalQuestSlot()
	local _, loadedSlot = getLoadedSessionState()
	if loadedSlot then
		return loadedSlot
	end

	local runtime = ensureQuestRuntime()
	local sessionManager = runtime and runtime.sessionManager
	if not isSessionManagerTable(sessionManager) then
		sessionManager = findLoadedSessionManager()
			or findSessionManagerFromQuestRuntime(runtime and runtime.questClient)
			or tryLoadSessionManagerModule()
		if runtime then
			runtime.sessionManager = sessionManager
		end
	end
	if not sessionManager or type(sessionManager.GetSlot) ~= "function" then
		return nil
	end

	local ok, slot = pcall(sessionManager.GetSlot, LP)
	if ok and slot then
		return slot
	end

	ok, slot = pcall(sessionManager.GetSlot)
	if ok and slot then
		return slot
	end

	if type(sessionManager.GetSaveFile) == "function" then
		local saveOk, saveFile = pcall(sessionManager.GetSaveFile, LP)
		if not saveOk or not saveFile then
			saveOk, saveFile = pcall(sessionManager.GetSaveFile)
		end
		if saveOk and saveFile and type(saveFile.Get) == "function" then
			local currentSlotOk, currentSlot = pcall(function()
				return saveFile:Get("CurrentSlot")
			end)
			local slotsOk, slots = pcall(function()
				return saveFile:Get("Slots")
			end)
			if currentSlotOk and currentSlot ~= nil and slotsOk and slots and type(slots.Get) == "function" then
				local directOk, directSlot = pcall(function()
					return slots:Get(currentSlot)
				end)
				if directOk and directSlot then
					return directSlot
				end
			end
		end
	end

	return nil
end

function getQuestRecord(slot, questName)
	if not slot or type(slot.Get) ~= "function" then
		return nil
	end

	local ok, record = pcall(function()
		return slot:Get({ "Quests", questName })
	end)
	if ok and record then
		return record
	end

	ok, record = pcall(function()
		local quests = slot:Get("Quests")
		if quests and type(quests.Get) == "function" then
			return quests:Get(questName)
		end
	end)
	if ok then
		return record
	end

	return nil
end

function getQuestRecordStatus(record)
	return getQuestRecordValue(record, "Status")
end

function normalizeQuestStatus(status)
	if status == nil then
		return nil
	end
	return tostring(status):lower()
end

function getQuestRecordValue(record, key)
	if not record then
		return nil
	end

	if type(record) == "table" and type(record.Get) == "function" then
		local ok, value = pcall(function()
			return record:Get(key)
		end)
		if ok then
			return value
		end
	end

	if type(record) == "table" then
		return record[key]
	end

	return nil
end

function getQuestDisplayNameByName(questName)
	local entry = QUEST_START_CATALOG_BY_NAME[questName]
	if entry then
		return getQuestDisplayNameFromEntry(entry)
	end

	local rawName = tostring(questName or "Quest")
	rawName = rawName:gsub("^[A-Z][A-Z]_", "")
	rawName = rawName:gsub("_", " ")
	return splitCamelWords(rawName)
end

function getQuestRecordEntries(quests)
	local entries = {}
	local seen = {}

	local function addEntry(questName, record)
		if questName == nil or record == nil then
			return
		end
		local key = tostring(questName)
		if seen[key] then
			return
		end
		seen[key] = true
		table.insert(entries, {
			Name = key,
			Record = record,
		})
	end

	if type(quests) == "table" then
		pcall(function()
			for questName, record in quests do
				addEntry(questName, record)
			end
		end)

		if type(quests.Export) == "function" then
			local ok, exported = pcall(function()
				return quests:Export()
			end)
			if ok and type(exported) == "table" then
				for questName, record in pairs(exported) do
					addEntry(questName, record)
				end
			end
		else
			for questName, record in pairs(quests) do
				if type(questName) == "string" and type(record) == "table" then
					addEntry(questName, record)
				end
			end
		end
	end

	return entries
end

function getLocalQuestMap()
	local slot = getLocalQuestSlot()
	local quests = slot and getQuestRecordValue(slot, "Quests") or nil
	if quests then
		return quests, slot
	end

	local runtime = ensureQuestRuntime()
	local sessionManager = runtime and runtime.sessionManager
	if not isSessionManagerTable(sessionManager) then
		sessionManager = findLoadedSessionManager()
			or findSessionManagerFromQuestRuntime(runtime and runtime.questClient)
			or tryLoadSessionManagerModule()
		if runtime then
			runtime.sessionManager = sessionManager
		end
	end

	if sessionManager and type(sessionManager.FastGetSlotValue) == "function" then
		local ok, directQuests = pcall(sessionManager.FastGetSlotValue, LP, "Quests")
		if ok and directQuests then
			return directQuests, slot
		end
		ok, directQuests = pcall(sessionManager.FastGetSlotValue, nil, "Quests")
		if ok and directQuests then
			return directQuests, slot
		end
	end

	return nil, slot
end

function getActiveQuestEmptyReason()
	local quests, slot = getLocalQuestMap()
	if not slot and not quests then
		local runtime = ensureQuestRuntime()
		return string.format(
			"Local slot was not resolved. SessionManager: %s, QuestClient: %s.",
			runtime and runtime.sessionManager and "found" or "missing",
			runtime and runtime.questClient and "found" or "missing"
		)
	end

	if not quests then
		return "Local slot resolved, but the Quests map is nil."
	end

	local counts = {
		total = 0,
		incomplete = 0,
		complete = 0,
		fail = 0,
		unknown = 0,
	}
	for _, entry in getQuestRecordEntries(quests) do
		counts.total += 1
		local status = normalizeQuestStatus(getQuestRecordStatus(entry.Record))
		if status == "incomplete" then
			counts.incomplete += 1
		elseif status == "complete" then
			counts.complete += 1
		elseif status == "fail" then
			counts.fail += 1
		else
			counts.unknown += 1
		end
	end

	if counts.total == 0 then
		return "Local slot and Quests map resolved, but no quest records were enumerable."
	end

	return string.format(
		"Scanned %d quest records: %d active, %d completed, %d failed, %d unknown.",
		counts.total,
		counts.incomplete,
		counts.complete,
		counts.fail,
		counts.unknown
	)
end

function getActiveQuestRecords()
	local results = {}
	local quests = getLocalQuestMap()
	if not quests then
		return results
	end

	for _, entry in getQuestRecordEntries(quests) do
		local questName = entry.Name
		local record = entry.Record
		if normalizeQuestStatus(getQuestRecordStatus(record)) == "incomplete" then
			table.insert(results, {
				Name = questName,
				Record = record,
				DisplayName = getQuestDisplayNameByName(questName),
				PathName = getQuestRecordValue(record, "CurrentPathName"),
				ObjectiveIndex = getQuestRecordValue(record, "CurrentObjectiveIndex"),
				Marked = getQuestRecordValue(record, "Marked") == true,
			})
		end
	end

	table.sort(results, function(left, right)
		local leftTimestamp = getQuestRecordValue(left.Record, "Timestamp") or 0
		local rightTimestamp = getQuestRecordValue(right.Record, "Timestamp") or 0
		if leftTimestamp == rightTimestamp then
			return left.DisplayName < right.DisplayName
		end
		return leftTimestamp < rightTimestamp
	end)

	return results
end

function getActiveQuestCount()
	local activeRecords = getActiveQuestRecords()
	if #activeRecords > 0 then
		return #activeRecords
	end

	local runtime = ensureQuestRuntime()
	local questClient = runtime and runtime.questClient
	local activeCount = 0
	if questClient and type(questClient.Quests) == "table" then
		for _ in questClient.Quests do
			activeCount += 1
		end
	end

	return activeCount
end

function getActiveQuestDescription(activeQuest)
	local parts = {}
	local pathName = activeQuest and activeQuest.PathName
	local objectiveIndex = activeQuest and activeQuest.ObjectiveIndex
	if pathName and pathName ~= "" then
		table.insert(parts, "Path: " .. tostring(pathName))
	end
	if objectiveIndex ~= nil then
		table.insert(parts, "Objective: " .. tostring(objectiveIndex))
	end
	if activeQuest and activeQuest.Marked then
		table.insert(parts, "Marked")
	end
	if #parts == 0 then
		return "Active in local slot."
	end
	return table.concat(parts, " | ")
end

function getLiveQuestByName(questName)
	local runtime = ensureQuestRuntime()
	local questClient = runtime and runtime.questClient
	if not questClient or type(questClient.GetQuestByName) ~= "function" then
		return nil
	end

	local ok, quest = pcall(function()
		return questClient:GetQuestByName(questName)
	end)
	if ok then
		return quest
	end

	return nil
end

function runActiveQuestAction(activeQuest)
	if not activeQuest or not activeQuest.Name then
		return
	end

	local questName = activeQuest.Name
	local liveQuest = getLiveQuestByName(questName) or waitForQuestByName(questName, 0.5)
	if liveQuest then
		local objective = getQuestObjectiveDefSafe(liveQuest)
		local displayName = getQuestDisplayName(liveQuest)
		if objective then
			local tutorialOk = showLocalTutorialDialog(getQuestGuideText(liveQuest, objective))
			if tutorialOk then
				setQuestStatusText(string.format("Guide shown for %s.", displayName))
			end

			local target = resolveObjectiveTeleportTarget(liveQuest)
			if target then
				promptQuestTeleport(target, displayName)
				return
			end

			questNotify(displayName, "Live quest found, but no teleport target was resolved.", Color3.fromRGB(255, 189, 89))
			return
		end
	end

	local entry = QUEST_START_CATALOG_BY_NAME[questName]
	if entry and entry.StarterNpc then
		local npc = getNpcModelFromProfile(entry.StarterNpc)
		local pos = npc and getInstancePosition(npc)
		if pos and farmTeleportToPosition(pos) then
			local npcLabel = npc:GetAttribute("DisplayName") or resolveProfileDisplayName(entry.StarterNpc)
			setQuestStatusText(string.format("Teleported to %s for %s.", npcLabel, activeQuest.DisplayName))
			questNotify(activeQuest.DisplayName, string.format("Teleported to %s.", npcLabel), Color3.fromRGB(57, 255, 74))
			return
		end
	end

	setQuestStatusText(string.format("%s is active in the slot, but no live quest target is available yet.", activeQuest.DisplayName))
	questNotify(activeQuest.DisplayName, "Quest is active in the local slot, but no live objective target could be resolved.", Color3.fromRGB(255, 189, 89))
end

function normalizeUniqueId(value)
	if value == nil then
		return nil
	end
	return tostring(value):gsub("%-", ""):lower()
end

function humanizeProfileName(profileName)
	local parts = {}
	for part in tostring(profileName or ""):gmatch("[^_]+") do
		table.insert(parts, splitCamelWords(part))
	end
	if #parts == 0 then
		return "NPC"
	end
	if parts[#parts] == "Shop" and #parts >= 2 then
		return parts[#parts - 1]
	end
	return parts[#parts]
end

function getNpcModelFromProfile(profileName)
	local runtime = ensureQuestRuntime()
	local profileIndex = runtime and runtime.profileIndex
	local normalizedProfileId = nil

	if profileIndex and type(profileIndex.GetProfileUniqueId) == "function" then
		local ok, profileId = pcall(profileIndex.GetProfileUniqueId, profileName)
		if ok and profileId then
			normalizedProfileId = normalizeUniqueId(profileId)
		end
	end

	for _, npc in CollectionService:GetTagged("NPC") do
		if npc and npc:IsA("Model") then
			local npcUniqueId = normalizeUniqueId(npc:GetAttribute("UniqueId"))
			if normalizedProfileId and npcUniqueId == normalizedProfileId then
				return npc
			end
			if npc.Name == profileName then
				return npc
			end
		end
	end

	return nil
end

function resolveProfileDisplayName(profileName)
	local npc = getNpcModelFromProfile(profileName)
	if npc then
		return npc:GetAttribute("DisplayName") or humanizeProfileName(profileName)
	end
	return humanizeProfileName(profileName)
end

function getInstancePosition(inst)
	if not inst or not inst.Parent then
		return nil
	end
	if inst:IsA("Attachment") then
		return inst.WorldPosition
	end
	if inst:IsA("BasePart") then
		return inst.Position
	end
	if inst:IsA("Model") then
		local primary = inst.PrimaryPart or inst:FindFirstChildWhichIsA("BasePart")
		if primary then
			return primary.Position
		end
		local ok, pivot = pcall(function()
			return inst:GetPivot()
		end)
		if ok then
			return pivot.Position
		end
	end

	local model = inst:FindFirstAncestorWhichIsA("Model")
	if model then
		return getInstancePosition(model)
	end

	local part = inst:FindFirstAncestorWhichIsA("BasePart")
	if part then
		return part.Position
	end

	return nil
end

function findDescendantSpawnPart(root)
	if not root then
		return nil
	end

	for _, desc in root:GetDescendants() do
		if desc.Name == "Part" and desc.Parent and desc.Parent.Name == "Marker" and desc:IsA("BasePart") then
			return desc
		end
	end

	for _, desc in root:GetDescendants() do
		if desc.Name == "Spawn" and desc:IsA("BasePart") then
			return desc
		end
	end

	return root:FindFirstChildWhichIsA("BasePart", true)
end

function resolveLocationPoint(locationName)
	if type(locationName) ~= "string" or locationName == "" then
		return nil, nil
	end

	local locations = workspace:FindFirstChild("Locations")
	local interiors = workspace:FindFirstChild("Interiors")
	local root = locations and (locations:FindFirstChild(locationName) or locations:FindFirstChild(locationName, true))
	if not root and interiors then
		root = interiors:FindFirstChild(locationName) or interiors:FindFirstChild(locationName, true)
	end
	if not root then
		return nil, nil
	end

	local marker = root:FindFirstChild("Marker")
	if marker and marker:FindFirstChild("Part") and marker.Part:IsA("BasePart") then
		return marker.Part.Position, marker.Part
	end

	local spawnPart = findDescendantSpawnPart(root)
	if spawnPart then
		return spawnPart.Position, spawnPart
	end

	local ok, pivot = pcall(function()
		return root:GetPivot()
	end)
	if ok then
		return pivot.Position, root
	end

	return nil, root
end

function resolveObjectiveTargetLabel(objective)
	if not objective then
		return "the current objective"
	end

	local params = objective.Parameters or {}
	if type(params.NPC) == "string" then
		return resolveProfileDisplayName(params.NPC)
	end
	if type(params.NPC) == "table" then
		for _, npcName in params.NPC do
			if type(npcName) == "string" and npcName ~= "" then
				return resolveProfileDisplayName(npcName)
			end
		end
	end
	if type(params.Location) == "string" and params.Location ~= "" then
		return params.Location
	end
	return objective.DisplayName or objective.Description or "the current objective"
end

function resolveQuestWaypointTarget(quest, objective)
	local runtime = ensureQuestRuntime()
	local questClient = runtime and runtime.questClient
	if not questClient then
		return nil
	end

	for _, waypoint in questClient.Waypoints do
		if waypoint and waypoint.Quest == quest then
			local pos = nil
			if waypoint.Adornee then
				pos = getInstancePosition(waypoint.Adornee)
			end
			if not pos and typeof(waypoint.Position) == "Vector3" then
				pos = waypoint.Position
			end
			if pos then
				return {
					Type = "Waypoint",
					Label = resolveObjectiveTargetLabel(objective),
					Position = pos,
					Instance = waypoint.Adornee,
				}
			end
		end
	end

	return nil
end

function resolveObjectiveTeleportTarget(quest)
	local objective = getQuestObjectiveDefSafe(quest)
	if not objective then
		return nil
	end

	local waypointTarget = resolveQuestWaypointTarget(quest, objective)
	if waypointTarget then
		return waypointTarget
	end

	local params = objective.Parameters or {}
	if type(params.NPC) == "string" then
		local npc = getNpcModelFromProfile(params.NPC)
		local pos = npc and getInstancePosition(npc)
		if pos then
			return {
				Type = "NPC",
				Label = resolveProfileDisplayName(params.NPC),
				Position = pos,
				Instance = npc,
			}
		end
	end

	if type(params.NPC) == "table" then
		for _, npcName in params.NPC do
			if type(npcName) == "string" then
				local npc = getNpcModelFromProfile(npcName)
				local pos = npc and getInstancePosition(npc)
				if pos then
					return {
						Type = "NPC",
						Label = resolveProfileDisplayName(npcName),
						Position = pos,
						Instance = npc,
					}
				end
			end
		end
	end

	if type(params.Location) == "string" then
		local pos, inst = resolveLocationPoint(params.Location)
		if pos then
			return {
				Type = "Location",
				Label = params.Location,
				Position = pos,
				Instance = inst,
			}
		end
	end

	return nil
end

function getQuestGuideText(quest, objective)
	local questName = getQuestDisplayName(quest)
	local objectiveText = nil
	if objective then
		objectiveText = objective.Description or objective.DisplayName
	end
	if not objectiveText or objectiveText == "" then
		objectiveText = "Follow the current quest objective."
	end
	return string.format("%s\n\n%s", questName, objectiveText)
end

function setQuestStatusText(text)
	state.questStatusText = tostring(text or "Quest guide idle.")
	refreshQuestStatusCard()
end

function getQuestStatusCardText()
	return string.format(
		"Guide: %s\nActive quests: %d\n%s",
		CONFIG.QuestGuideEnabled and "enabled" or "disabled",
		getActiveQuestCount(),
		state.questStatusText or "Quest guide idle."
	)
end

function refreshQuestStatusCard()
	local card = state.questStatusCard
	if not card or not card.Parent then
		return
	end
	local content = card:FindFirstChild("Content", true)
	if content and content:IsA("TextLabel") then
		content.Text = getQuestStatusCardText()
	end
end

function waitForQuestByName(questName, timeout)
	local deadline = tick() + (timeout or 5)
	while tick() < deadline do
		local runtime = ensureQuestRuntime()
		local questClient = runtime and runtime.questClient
		if questClient and type(questClient.GetQuestByName) == "function" then
			local ok, quest = pcall(function()
				return questClient:GetQuestByName(questName)
			end)
			if ok and quest then
				return quest
			end
		end
		task.wait(0.1)
	end
	return nil
end

function clearQuestGuideQueue()
	table.clear(state.questPendingOrder)
	table.clear(state.questPendingLookup)
end

function waitForObjectiveToAdvance(quest)
	local entry = QUEST_START_CATALOG_BY_NAME[quest and quest.Name or ""]
	local starterNpc = entry and entry.StarterNpc or nil
	local lastObjective = getQuestObjectiveDefSafe(quest)
	local deadline = tick() + 2.5

	while starterNpc and tick() < deadline do
		lastObjective = getQuestObjectiveDefSafe(quest)
		if not lastObjective then
			break
		end

		local params = lastObjective.Parameters or {}
		local objectiveNpc = params.NPC
		if type(objectiveNpc) == "table" then
			objectiveNpc = objectiveNpc[1]
		end

		if lastObjective.Kind ~= "TalkToNPC" or objectiveNpc ~= starterNpc then
			break
		end

		task.wait(0.12)
	end

	return lastObjective
end

function showLocalTutorialDialog(text)
	local runtime = ensureQuestRuntime()
	local dialogUi = runtime and runtime.dialogUi
	if not dialogUi then
		return false, "Dialog UI not found."
	end

	local clientTagData = LP and LP:FindFirstChild("ClientTagData")
	local inputSignal = dialogUi.InputRegistered
	local finished = false
	local connection = nil

	if dialogUi.IsOpen then
		pcall(function()
			dialogUi:Close()
		end)
		task.wait(0.05)
	end

	if clientTagData then
		pcall(function()
			clientTagData:AddTag("InTutorial")
		end)
	end

	pcall(function()
		dialogUi:Open()
	end)
	pcall(function()
		dialogUi:Update({
			Speaker = "",
			Text = ("<Color Color='rgb(57, 255, 74)'>%s</Color>"):format(text),
		})
	end)

	if inputSignal then
		if type(inputSignal.Once) == "function" then
			pcall(function()
				inputSignal:Once(function()
					finished = true
				end)
			end)
		elseif type(inputSignal.Connect) == "function" then
			local ok, conn = pcall(function()
				return inputSignal:Connect(function()
					finished = true
				end)
			end)
			if ok then
				connection = conn
			end
		end
	end

	local deadline = tick() + 12
	while not finished and tick() < deadline do
		task.wait(0.05)
	end

	if connection then
		pcall(function()
			connection:Disconnect()
		end)
	end
	pcall(function()
		dialogUi:Close()
	end)
	if clientTagData then
		pcall(function()
			clientTagData:RemoveTag("InTutorial")
		end)
	end

	return true
end

function promptQuestTeleport(target, questDisplayName)
	local runtime = ensureQuestRuntime()
	local popup = runtime and runtime.popup
	if not popup then
		return false, "Popup UI not found."
	end

	local targetLabel = target and target.Label or "the quest objective"
	local janitor = createLocalJanitor()

	popup:Setup(janitor, {
		Title = "Teleportar?",
		Description = {
			Text = string.format("Deseja teleportar para %s em %s?", targetLabel, questDisplayName),
			Size = UDim2.fromScale(0.72, 0.3),
		},
		Options = { "Teleportar", "Cancelar" },
	}, function()
		if target and typeof(target.Position) == "Vector3" and farmTeleportToPosition(target.Position) then
			setQuestStatusText(string.format("Teleported to %s.", targetLabel))
			questNotify("Quest Teleport", string.format("Teleported to %s.", targetLabel), Color3.fromRGB(57, 255, 74))
		else
			setQuestStatusText(string.format("Failed to teleport to %s.", targetLabel))
			questNotify("Quest Teleport", string.format("Could not teleport to %s.", targetLabel), Color3.fromRGB(255, 104, 104))
		end
	end)

	janitor:Cleanup()
	return true
end

function processQuestGuideQueue()
	if state.questGuideBusy then
		return
	end
	if not CONFIG.QuestGuideEnabled then
		clearQuestGuideQueue()
		return
	end

	local nextQuestName = table.remove(state.questPendingOrder, 1)
	if not nextQuestName then
		return
	end
	state.questPendingLookup[nextQuestName] = nil
	state.questGuideBusy = true

	task.spawn(function()
		local success, err = pcall(function()
			local dialogDeadline = tick() + 20
			while LP and LP:GetAttribute("GameState") == "InDialog" and tick() < dialogDeadline do
				task.wait(0.1)
			end

			task.wait(0.25)

			local quest = waitForQuestByName(nextQuestName, 6)
			if not quest then
				setQuestStatusText("Quest started, but no live quest object was found.")
				return
			end

			local objective = waitForObjectiveToAdvance(quest)
			local guideText = getQuestGuideText(quest, objective)
			local questDisplayName = getQuestDisplayName(quest)
			local ok = showLocalTutorialDialog(guideText)

			if ok then
				setQuestStatusText(string.format("Guide shown for %s.", questDisplayName))
			else
				setQuestStatusText(string.format("Guide fallback used for %s.", questDisplayName))
			end

			local target = resolveObjectiveTeleportTarget(quest)
			if target then
				promptQuestTeleport(target, questDisplayName)
			else
				questNotify("Quest Guide", string.format("No teleport target found for %s.", questDisplayName), Color3.fromRGB(255, 189, 89))
			end
		end)

		if not success then
			setQuestStatusText("Quest guide error: " .. tostring(err))
			questNotify("Quest Guide", tostring(err), Color3.fromRGB(255, 104, 104))
		end

		state.questGuideBusy = false
		if #state.questPendingOrder > 0 then
			processQuestGuideQueue()
		end
	end)
end

function queueQuestGuide(quest)
	if not quest or not quest.Name or state.questPendingLookup[quest.Name] then
		return
	end
	state.questPendingLookup[quest.Name] = true
	table.insert(state.questPendingOrder, quest.Name)
	setQuestStatusText(string.format("Queued guide for %s.", getQuestDisplayName(quest)))
	processQuestGuideQueue()
end

function initQuestGuideHooks()
	if state.questSignalConnected then
		return
	end

	task.spawn(function()
		local deadline = tick() + 30
		while not state.questSignalConnected and tick() < deadline do
			local runtime = ensureQuestRuntime()
			local questClient = runtime and runtime.questClient
			if questClient and questClient.QuestStarted and type(questClient.QuestStarted.Connect) == "function" then
				state.questSignalConnected = true
				table.insert(state.connections, questClient.QuestStarted:Connect(function(quest)
					if CONFIG.QuestGuideEnabled then
						queueQuestGuide(quest)
					else
						setQuestStatusText(string.format("%s started. Enable the guide toggle to show the tutorial popup.", getQuestDisplayName(quest)))
					end
				end))
				setQuestStatusText("Quest runtime connected.")
				break
			end
			task.wait(1)
		end
	end)
end

function getQuestStartTarget(entry)
	if not entry then
		return false, "Unknown quest entry.", nil
	end

	if entry.StoryControlled then
		return false, entry.StoryNote or "Story-controlled quest.", nil
	end

	local slot = getLocalQuestSlot()
	if not slot then
		return false, "Quest data is not ready yet.", nil
	end

	local record = getQuestRecord(slot, entry.Name)
	if record then
		local status = getQuestRecordStatus(record)
		if status == "incomplete" then
			return false, "Quest is already active.", nil
		end
		if status == "complete" then
			return false, "Quest is already completed.", nil
		end
		if status == "fail" then
			return false, "Quest already exists in your save data.", nil
		end
		return false, "Quest state is already registered.", nil
	end

	local inPrologue = false
	local ok = pcall(function()
		inPrologue = slot:Get("InPrologue") == true
	end)
	if ok and inPrologue then
		return false, "Unavailable during the prologue.", nil
	end

	local npc = entry.StarterNpc and getNpcModelFromProfile(entry.StarterNpc) or nil
	if not npc then
		return false, "Starter NPC is not available right now.", nil
	end

	local dialogUtil = ensureQuestRuntime().dialogUtil
	local canInteract = npc:GetAttribute("Dialog") ~= nil
	if dialogUtil and type(dialogUtil.CanInteract) == "function" then
		local interactOk, interactResult = pcall(dialogUtil.CanInteract, LP, npc)
		if interactOk then
			canInteract = interactResult == true
		end
	end
	if not canInteract then
		return false, "Starter NPC cannot be interacted with right now.", nil
	end

	local pos = getInstancePosition(npc)
	if not pos then
		return false, "Starter NPC has no valid position.", nil
	end

	local npcLabel = npc:GetAttribute("DisplayName") or resolveProfileDisplayName(entry.StarterNpc)
	return true, ("Starter NPC: %s"):format(npcLabel), {
		Type = "NPC",
		Label = npcLabel,
		Position = pos,
		Instance = npc,
	}
end

function runQuestStartTeleport(entry)
	local available, reason, target = getQuestStartTarget(entry)
	if not available or not target then
		setQuestStatusText(string.format("%s unavailable: %s", getQuestDisplayNameFromEntry(entry), reason))
		questNotify(getQuestDisplayNameFromEntry(entry), reason, Color3.fromRGB(255, 104, 104))
		return
	end

	if farmTeleportToPosition(target.Position) then
		setQuestStatusText(string.format("Teleported to %s for %s.", target.Label, getQuestDisplayNameFromEntry(entry)))
		questNotify(getQuestDisplayNameFromEntry(entry), string.format("Teleported to %s.", target.Label), Color3.fromRGB(57, 255, 74))
	else
		setQuestStatusText(string.format("Failed to teleport to %s.", target.Label))
		questNotify(getQuestDisplayNameFromEntry(entry), string.format("Could not teleport to %s.", target.Label), Color3.fromRGB(255, 104, 104))
	end
end
-- ============================================================
-- LOOPS
-- ============================================================

function startLoops()
	for _, conn in state.connections do
		conn:Disconnect()
	end
	table.clear(state.connections)

	table.insert(state.connections, RunService.Heartbeat:Connect(function()
		local now = tick()
		local dt = math.clamp(now - state.lastHeartbeat, 1 / 120, 0.1)
		state.lastHeartbeat = now

		if CONFIG.AutoFarmEnabled then
			releaseFarmMouse()
		end

		if CONFIG.CharacterSpeedEnabled
			or CONFIG.CharacterJumpEnabled
			or CONFIG.CharacterNoFallLanding
			or CONFIG.CharacterAntiSit
			or CONFIG.CharacterNoClip
			or CONFIG.CharacterPlatformStandGuard then
			applyCharacterModifiers()
		end

		if shouldUseMeleeHijack() then
			doMeleeSwing()
		end
		if CONFIG.GatherEnabled then doGather() end
		if CONFIG.BreakEnabled then doBreak() end
		if CONFIG.SpamEnabled and now - state.lastSpam >= CONFIG.SpamCooldown then
			state.lastSpam = now
			doSpam()
		end
		if CONFIG.AutoBowlingEnabled and state.bowlingInMinigame
			and not state.bowlingThrowing
			and now - state.bowlingLastAutoThrow >= CONFIG.BowlingThrowInterval then
			state.bowlingLastAutoThrow = now
			task.spawn(doBowlingThrow)
		end
	end))

	if LP then
		function onCharacterSpawned(char)
			setupCharacterHooks(char)
			if CONFIG.AutoFarmEnabled and CONFIG.AutoEquipStrongestOnRespawn then
				equipStrongestOnRespawn(char)
			end
			if CONFIG.AutoFarmEnabled and state.farmRespawnPending then
				resumeFarmAfterRespawn(char)
			else
				setupFarmAutoRespawn(char)
			end
		end

		table.insert(state.connections, LP.CharacterAdded:Connect(function(char)
			task.defer(function()
				onCharacterSpawned(char)
			end)
		end))
		if LP.Character then
			task.defer(function()
				onCharacterSpawned(LP.Character)
			end)
		end
	end

	table.insert(state.connections, UIS.InputBegan:Connect(function(input, processed)
		if processed then return end
		if input.KeyCode == CONFIG.MenuKey then
			state.menuOpen = not state.menuOpen
			if _G.PentestUI then
				_G.PentestUI.SetVisible(state.menuOpen)
			end
		end
	end))
end

function waitReady()
	repeat task.wait() until game:IsLoaded()
	if not LP then LP = Players.PlayerAdded:Wait() end
	pcall(function() LP:WaitForChild("ClientTagData", 120) end)
	task.wait(1.5)
	discoverRemotes()
end


