		Callback = function(v)
			CONFIG.CharacterWalkSpeed = math.floor(v + 0.5)
			applyCharacterModifiers()
		end,
	})
	Character:AddToggle({
		Title = "Custom Jump",
		Description = "Uses Humanoid.JumpPower locally and keeps it refreshed.",
		Default = CONFIG.CharacterJumpEnabled,
		Callback = function(v)
			CONFIG.CharacterJumpEnabled = v
			applyCharacterModifiers()
		end,
	})
	Character:AddSlider({
		Title = "Jump Power",
		Min = 0, Max = 180, Default = CONFIG.CharacterJumpPower, Increment = 1,
		Callback = function(v)
			CONFIG.CharacterJumpPower = math.floor(v + 0.5)
			applyCharacterModifiers()
		end,
	})
	Character:AddButton({
		Title = "Force Jump",
		Description = "Locally forces the humanoid into the Jumping state.",
		ButtonText = "Jump",
		Icon = "play",
		Callback = function()
			local char = getCharacter()
			local humanoid = char and char:FindFirstChildOfClass("Humanoid")
			if humanoid then
				humanoid:ChangeState(Enum.HumanoidStateType.Jumping)
			end
		end,
	})
	Character:AddButton({
		Title = "Reset Movement",
		Description = "Disables speed, jump, no-clip, anti-sit, and PlatformStand guard settings.",
		ButtonText = "Reset",
		Icon = "refresh",
		Callback = function()
			CONFIG.CharacterSpeedEnabled = false
			CONFIG.CharacterJumpEnabled = false
			CONFIG.CharacterNoClip = false
			CONFIG.CharacterAntiSit = false
			CONFIG.CharacterPlatformStandGuard = false
			task.defer(buildNeonUI)
		end,
	})

	Character:AddSection("Fall / Physics")

	local characterStatusCard = Character:AddParagraph({
		Title = "Character Status",
		Content = "Fall damage inspection: the client module listens for the HardLanding attribute and applies local landing effects. Server-side health damage was not visible in the inspected client modules.",
