		end,
	})

	local farmStatsCard = Farming:AddParagraph({
		Title = "Farm Statistics",
		Content = getFarmStatsText(),
	})

	Golf:AddParagraph({
		Title = "Gold Golf Hard",
		Content = "Auto Golf with RenderStepped aim, moving-target prediction, and retry when a fired target still exists.",
	})

	Golf:AddSection("Auto Play")

	Golf:AddToggle({
		Title = "Auto Golf Hard",
		Description = "Enter Gold Golf Hard Mode and enable this to play all 5 targets automatically.",
		Default = CONFIG.AutoGolfEnabled,
		Callback = function(v)
			if v then startAutoGolfHard() else stopAutoGolfHard() end
		end,
	})

	Golf:AddButton({
		Title = "Reset Auto Golf",
		Description = "Clears the internal round, target, and motion calibration state.",
		ButtonText = "Reset",
		Icon = "refresh",
		Callback = function()
			resetAutoGolfHard()
		end,
	})
	local metricBowling = createMetric(Bowling, "Bowling Status", state.bowlingStatus)

	Bowling:AddParagraph({
		Title = "Meerkat Bowling",
		Content = "Integrated strike hijack (BowlingStrikeHijack). Enter the minigame, enable Auto Bowling, and each round forces a strike.",
	})

	Bowling:AddSection("Auto Play")

	Bowling:AddToggle({
		Title = "Auto Bowling",
		Description = "Throws automatically in Meerkat Bowling.",
		Default = CONFIG.AutoBowlingEnabled,
		Callback = function(v)
			if v then startAutoBowling() else stopAutoBowling() end
		end,
	})
	Bowling:AddToggle({
		Title = "Auto Equip Bowling Ball",
		Default = CONFIG.BowlingAutoEquipBall,
		Callback = function(v) CONFIG.BowlingAutoEquipBall = v end,
	})
	Bowling:AddSlider({
		Title = "Throw interval",
		Min = 2, Max = 12, Default = CONFIG.BowlingThrowInterval, Increment = 0.5,
		Suffix = "s",
		Callback = function(v) CONFIG.BowlingThrowInterval = v end,
	})

	Bowling:AddSection("Strike Hijack")

	Bowling:AddToggle({
		Title = "Strike Hijack",
		Description = "Forces strike score and pin knock.",
		Default = CONFIG.BowlingStrikeEnabled,
		Callback = function(v)
			CONFIG.BowlingStrikeEnabled = v
			if v then hookBowlingGameCalls() end
		end,
	})
	Bowling:AddToggle({
		Title = "Remove obstacles",
		Default = CONFIG.BowlingRemoveObstacles,
		Callback = function(v) CONFIG.BowlingRemoveObstacles = v end,
	})
	Bowling:AddToggle({
		Title = "Ball boost",
		Default = CONFIG.BowlingBoostBall,
		Callback = function(v) CONFIG.BowlingBoostBall = v end,
	})
	Bowling:AddToggle({
		Title = "Knock pins before count",
		Default = CONFIG.BowlingKnockPinsBeforeCount,
		Callback = function(v) CONFIG.BowlingKnockPinsBeforeCount = v end,
	})
	Bowling:AddToggle({
		Title = "Force network score",
		Default = CONFIG.BowlingForceScoreOnNetwork,
		Callback = function(v) CONFIG.BowlingForceScoreOnNetwork = v end,
	})
	Bowling:AddSlider({
		Title = "Pins per round",
		Min = 1, Max = 10, Default = CONFIG.BowlingPinsPerRound, Increment = 1,
		Callback = function(v) CONFIG.BowlingPinsPerRound = math.floor(v + 0.5) end,
	})
	Bowling:AddSlider({
		Title = "Ball speed",
		Min = 80, Max = 400, Default = CONFIG.BowlingBallSpeed, Increment = 5,
		Callback = function(v) CONFIG.BowlingBallSpeed = math.floor(v + 0.5) end,
	})
	Bowling:AddSlider({
		Title = "Pin knock delay",
		Min = 1, Max = 5, Default = CONFIG.BowlingKnockPinsDelay, Increment = 0.05,
		Suffix = "s",
		Callback = function(v) CONFIG.BowlingKnockPinsDelay = v end,
	})

	Bowling:AddSection("Actions")

	Bowling:AddButton({
		Title = "Manual throw",
		Description = "Activates the equipped ball now.",
		ButtonText = "Throw",
		Icon = "play",
		Callback = function() doBowlingThrow() end,
	})
	Bowling:AddButton({
		Title = "Knock pins",
		Description = "Physically knocks every pin in the lane.",
		ButtonText = "Knock",
		Icon = "target",
		Callback = function() knockBowlingPins() end,
	})
	Bowling:AddButton({
		Title = "Clear obstacles",
		Description = "Removes Wall / MovingWall from the minigame.",
		ButtonText = "Clear",
		Icon = "clear",
		Callback = function() clearBowlingObstacles() end,
	})

	Tuning:AddSection("Gather And Break")

	Tuning:AddSlider({
		Title = "Gather Cooldown",
		Min = 0.05, Max = 1, Default = CONFIG.GatherCooldown, Increment = 0.01,
		Suffix = "s",
		Callback = function(v) CONFIG.GatherCooldown = v end,
	})
	Tuning:AddSlider({
		Title = "Gather Max Per Tick",
		Min = 1, Max = 15, Default = CONFIG.GatherMaxPerTick, Increment = 1,
		Callback = function(v) CONFIG.GatherMaxPerTick = math.floor(v + 0.5) end,
	})
	Tuning:AddSlider({
		Title = "Break Cooldown",
		Min = 0.05, Max = 1, Default = CONFIG.BreakCooldown, Increment = 0.01,
		Suffix = "s",
		Callback = function(v) CONFIG.BreakCooldown = v end,
	})
	Tuning:AddSlider({
		Title = "Break Max Per Tick",
		Min = 1, Max = 15, Default = CONFIG.BreakMaxPerTick, Increment = 1,
		Callback = function(v) CONFIG.BreakMaxPerTick = math.floor(v + 0.5) end,
	})

	Tuning:AddSection("Stress")

	Tuning:AddToggle({
		Title = "Spam Stress",
		Default = CONFIG.SpamEnabled,
		Callback = function(v) CONFIG.SpamEnabled = v end,
	})
	Tuning:AddSlider({
		Title = "Spam Parallel Calls",
		Min = 1, Max = 10, Default = CONFIG.SpamParallel, Increment = 1,
		Callback = function(v) CONFIG.SpamParallel = math.floor(v + 0.5) end,
	})
	Tuning:AddSlider({
		Title = "Spam Cooldown",
		Min = 0.01, Max = 0.25, Default = CONFIG.SpamCooldown, Increment = 0.01,
		Suffix = "s",
		Callback = function(v) CONFIG.SpamCooldown = v end,
	})

	function refreshStatus()
		metricRemotes.Set(#state.remotes)
		metricMelee.Set(state.meleeNet and "OK" or "N/A")
		metricNpcs.Set(#getAliveNPCs())
		metricSpawners.Set(#state.farmLocations)
		local farmLine = CONFIG.AutoFarmEnabled and ("\nFarm: " .. state.farmStatus) or ""
		local bowlingLine = (CONFIG.AutoBowlingEnabled or state.bowlingInMinigame)
			and ("\nBowling: " .. state.bowlingStatus) or ""
		metricBowling.Set(state.bowlingInMinigame and ("in-game · " .. state.bowlingStatus) or state.bowlingStatus)
		setParagraphContent(farmStatsCard, getFarmStatsText())
		setParagraphContent(statusCard, ("Cached remotes: %d%s%s\nF6 toggles this menu."):format(
			#state.remotes,
			farmLine,
			bowlingLine
		))
		refreshQuestStatusCard()
	end
	refreshStatus()

	function setVisible(v)
		state.menuOpen = v == true
		Window:SetVisible(state.menuOpen)
	end

	local toggleBtn = Instance.new("TextButton")
	toggleBtn.Name = "AccelerantHubToggle"
	toggleBtn.AnchorPoint = Vector2.new(0, 0.5)
	toggleBtn.Position = UDim2.new(0, 16, 0.5, 0)
	toggleBtn.Size = UDim2.fromOffset(54, 54)
	toggleBtn.BackgroundColor3 = theme.Accent
	toggleBtn.Text = "✦"
	toggleBtn.Font = Enum.Font.GothamBlack
	toggleBtn.TextSize = 20
	toggleBtn.TextColor3 = theme.ButtonText
	toggleBtn.AutoButtonColor = false
	toggleBtn.ZIndex = 10

	local toggleParent = pg
	pcall(function()
		local probe = Instance.new("Folder")
		probe.Parent = CoreGui
		probe:Destroy()
		toggleParent = CoreGui
	end)

	local toggleGui = Instance.new("ScreenGui")
	toggleGui.Name = "AccelerantHubNeonToggle"
	toggleGui.ResetOnSpawn = false
	toggleGui.IgnoreGuiInset = true
	toggleGui.DisplayOrder = 100001
	toggleGui.Parent = toggleParent
	toggleBtn.Parent = toggleGui

	AddCorner(toggleBtn, 15)
	local toggleStroke = AddStroke(toggleBtn, theme.Accent2, 0.14, 1)
	AddGradient(toggleBtn, { theme.AccentDeep, theme.Accent, theme.Accent2 }, 28)
	local toggleScale = AddScale(toggleBtn, 1)
	local toggleLogoAsset = ensureAccelerantLogoAsset()
	if toggleLogoAsset then
		toggleBtn.Text = ""
		local toggleLogo = Instance.new("ImageLabel")
		toggleLogo.Name = "Logo"
		toggleLogo.BackgroundTransparency = 1
		toggleLogo.Position = UDim2.fromOffset(5, 7)
		toggleLogo.Size = UDim2.fromOffset(44, 40)
		toggleLogo.Image = toggleLogoAsset
		toggleLogo.ScaleType = Enum.ScaleType.Fit
		toggleLogo.ZIndex = toggleBtn.ZIndex + 1
		toggleLogo.Parent = toggleBtn
	end

	toggleBtn.MouseEnter:Connect(function()
		Tween(toggleBtn, FAST_EASING, {
			BackgroundColor3 = theme.Accent2,
		})
		Tween(toggleStroke, FAST_EASING, {
			Color = theme.Glow,
			Transparency = 0.02,
		})
		Tween(toggleScale, FAST_EASING, {
			Scale = 1.08,
		})
	end)

	toggleBtn.MouseLeave:Connect(function()
		Tween(toggleBtn, FAST_EASING, {
			BackgroundColor3 = theme.Accent,
		})
		Tween(toggleStroke, FAST_EASING, {
			Color = theme.Accent2,
			Transparency = 0.14,
		})
		Tween(toggleScale, FAST_EASING, {
			Scale = 1,
		})
	end)

	toggleBtn.MouseButton1Down:Connect(function()
		Tween(toggleScale, FAST_EASING, {
			Scale = 0.94,
		})
	end)

	toggleBtn.MouseButton1Up:Connect(function()
		Tween(toggleScale, FAST_EASING, {
			Scale = 1.08,
		})
	end)

	toggleBtn.MouseButton1Click:Connect(function()
		setVisible(not state.menuOpen)
	end)

	_G.PentestUI = {
		SetVisible = setVisible,
		Refresh = refreshStatus,
		Gui = Window.Gui,
		Window = Window,
	}
	setVisible(true)
	log("Neon menu opened - press F6 to toggle")
end
-- ============================================================
-- BOOT
-- ============================================================

task.spawn(function()
	local ok, err = pcall(function()
		waitReady()
		local loaded, loadResult = loadMenuConfig()
		if loaded then
			log("Config auto-loaded from " .. tostring(loadResult))
		elseif tostring(loadResult) ~= "config file not found" then
			warnLog("Config auto-load failed: " .. tostring(loadResult))
		end
		initBowlingModule()
		if not loaded then
			pcall(applyCurrentAppearanceToConfig)
		end
		syncRuntimeFromConfig()
		buildNeonUI()
		startLoops()
		initQuestGuideHooks()
		log("Accelerant Hub active")
	end)
	if not ok then
		warnLog("ERROR: " .. tostring(err))
	end
end)

_G.ScarifPentest = {
	Config = CONFIG,
	State = state,
	Discover = discoverRemotes,
	StartFarm = startAutoFarm,
	StopFarm = stopAutoFarm,
	ScanFarmLocations = function(force) return scanFarmLocations(force) end,
	EquipStrongest = equipStrongestTool,
	EquipStrongestOnRespawn = equipStrongestOnRespawn,
	StartBowling = startAutoBowling,
	StopBowling = stopAutoBowling,
	StartGolf = startAutoGolfHard,
	StopGolf = stopAutoGolfHard,
	ResetGolf = resetAutoGolfHard,
	SaveConfig = saveMenuConfig,
	LoadConfig = loadMenuConfig,
}

_G.BowlingStrikeHijack = {
	Config = CONFIG,
	ClearObstacles = clearBowlingObstacles,
	KnockPins = knockBowlingPins,
	BoostBall = boostBowlingBallTowardPins,
	Throw = doBowlingThrow,
}
